/* eslint-env serviceworker */
/* global clients */

// StudyFriend Service Worker - Browser Push Notifications
// This file MUST be in the /public folder to be served at the root URL

self.addEventListener('push', function (event) {
  if (!event.data) return;

  let data = {};
  try {
    data = event.data.json();
  } catch {
    data = { title: 'StudyFriend', body: event.data.text() };
  }

  const title = data.title || 'StudyFriend';
  const options = {
    body: data.body || 'You have a new notification.',
    icon: data.icon || '/icons.svg',
    badge: '/icons.svg',
    tag: data.tag || 'studyfriend-notification',
    renotify: true,
    vibrate: [200, 100, 200],
    data: {
      url: data.url || '/',
    },
  };

  event.waitUntil(self.registration.showNotification(title, options));
});

self.addEventListener('notificationclick', function (event) {
  event.notification.close();

  const targetUrl = event.notification.data?.url || '/';

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function (clientList) {
      // If a tab is already open at this origin, focus it and navigate
      for (const client of clientList) {
        if (client.url.includes(self.location.origin) && 'focus' in client) {
          client.navigate(targetUrl);
          return client.focus();
        }
      }
      // Otherwise open a new tab
      if (clients.openWindow) {
        return clients.openWindow(targetUrl);
      }
    })
  );
});

self.addEventListener('install', () => {
  self.skipWaiting();
});

self.addEventListener('activate', () => {
  // eslint-disable-next-line no-undef
  clients.claim();
});

import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { GoogleOAuthProvider } from '@react-oauth/google';
import { AuthProvider } from './context/AuthContext';
import { SocketProvider } from './context/SocketContext';
import { ThemeProvider } from './context/ThemeContext';
import ProtectedRoute from './components/ProtectedRoute';
import AdminRoute from './components/AdminRoute';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import { Box, Drawer } from '@mui/material';
import { useState } from 'react';
import Landing from './pages/Landing';
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Browse from './pages/Browse';
import Matches from './pages/Matches';
import Connections from './pages/Connections';
import Sessions from './pages/Sessions';
import StudyRoom from './pages/StudyRoom';
import PublicGroups from './pages/PublicGroups';
import Messages from './pages/Messages';
import Support from './pages/Support';
import UserProfile from './pages/UserProfile';
import EditProfile from './pages/EditProfile';
import PomodoroFocus from './pages/PomodoroFocus'; // Added
import AdminPanel from './pages/AdminPanel';
import ForgotPassword from './pages/ForgotPassword';
import ResetPassword from './pages/ResetPassword';
import Billing from './pages/Billing';
import SupportWidget from './components/SupportWidget';
import Onboarding from './pages/Onboarding';
import Leaderboard from './pages/Leaderboard';
import GlobalAnnouncementBanner from './components/GlobalAnnouncementBanner';
import GroupDetails from './pages/GroupDetails';
import StudyMap from './pages/StudyMap';
import PendingApproval from './pages/PendingApproval';
import OrgAdminDashboard from './pages/OrgAdminDashboard';
import OrgAdminLogin from './pages/OrgAdminLogin';
import Gamification from './pages/Gamification';
import Arcade from './pages/Arcade';

import AIAssistantWidget from './components/AIAssistantWidget';
import GlobalMessengerWidget from './components/GlobalMessengerWidget';
import CustomCursor from './components/CustomCursor';
import CommandPalette from './components/CommandPalette';
import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';

class GlobalErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(error) { return { error }; }
  render() {
    if (this.state.error) {
      return (
        <div style={{ color: '#fff', padding: '2rem', background: '#991b1b', zIndex: 99999, position: 'fixed', inset: 0, overflow: 'auto' }}>
          <h1 style={{ fontWeight: 900 }}>Fatal React Component Crash</h1>
          <p style={{ fontWeight: 700, fontSize: '1.25rem' }}>{this.state.error.message}</p>
          <pre style={{ fontSize: '1rem', whiteSpace: 'pre-wrap', background: 'rgba(0,0,0,0.5)', padding: '1rem', borderRadius: '8px' }}>{this.state.error.stack}</pre>
        </div>
      );
    }
    return this.props.children;
  }
}

const Layout = ({ children }) => {
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  return (
    <Box sx={{ display: 'flex', minHeight: '100vh', p: { xs: 0, md: 2 }, gap: { xs: 0, md: 2 } }}>
      <CommandPalette />

      {/* Mobile Drawer */}
      <Drawer anchor="left" open={mobileOpen} onClose={() => setMobileOpen(false)} PaperProps={{ sx: { width: 280, border: 'none' } }}>
        <Sidebar mobileOpen={mobileOpen} setMobileOpen={setMobileOpen} />
      </Drawer>

      {/* Desktop Sidebar */}
      <Sidebar mobileOpen={false} setMobileOpen={() => {}} />

      {/* Main Content Area */}
      <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'column', minWidth: 0, overflowX: 'hidden' }}>
        <GlobalAnnouncementBanner />
        <Navbar onMenuClick={() => setMobileOpen(true)} />
        <Box component="main" sx={{ flexGrow: 1, p: 0, overflowX: 'hidden' }}>
          <AnimatePresence mode="wait">
            <motion.div
              key={location.pathname}
              initial={{ opacity: 0, y: 15, filter: 'blur(4px)' }}
              animate={{ opacity: 1, y: 0, filter: 'blur(0px)' }}
              exit={{ opacity: 0, y: -15, filter: 'blur(4px)' }}
              transition={{ duration: 0.3, ease: 'easeOut' }}
            >
              {children}
            </motion.div>
          </AnimatePresence>
        </Box>
      </Box>

      <SupportWidget />
      <GlobalMessengerWidget />
      <AIAssistantWidget />
    </Box>
  );
};

export default function App() {
  const clientId = import.meta.env.VITE_GOOGLE_CLIENT_ID || '1000000000000-dummyclientid.apps.googleusercontent.com';

  return (
    <GoogleOAuthProvider clientId={clientId}>
      <GlobalErrorBoundary>
      <ThemeProvider>
      <CustomCursor />
      <AuthProvider>
        <SocketProvider>
          <BrowserRouter>
            <Toaster position="top-right" toastOptions={{ duration: 3000 }} />
            <Routes>
              <Route path="/login" element={<Login />} />
              <Route path="/org-admin-login" element={<OrgAdminLogin />} />
              <Route path="/register" element={<Register />} />
              <Route path="/onboarding" element={<ProtectedRoute><Onboarding /></ProtectedRoute>} />
              <Route path="/forgot-password" element={<ForgotPassword />} />
              <Route path="/reset-password/:token" element={<ResetPassword />} />
              <Route path="/" element={<Landing />} />
              <Route path="/dashboard" element={<ProtectedRoute><Layout><Dashboard /></Layout></ProtectedRoute>} />
              <Route path="/browse" element={<ProtectedRoute><Layout><Browse /></Layout></ProtectedRoute>} />
              <Route path="/matches" element={<ProtectedRoute><Layout><Matches /></Layout></ProtectedRoute>} />
              <Route path="/connections" element={<ProtectedRoute><Layout><Connections /></Layout></ProtectedRoute>} />
              <Route path="/gamification" element={<ProtectedRoute><Layout><Gamification /></Layout></ProtectedRoute>} />
              <Route path="/arcade" element={<ProtectedRoute><Layout><Arcade /></Layout></ProtectedRoute>} />
              <Route path="/sessions" element={<ProtectedRoute><Layout><Sessions /></Layout></ProtectedRoute>} />
              <Route path="/leaderboard" element={<ProtectedRoute><Layout><Leaderboard /></Layout></ProtectedRoute>} />
              <Route path="/groups" element={<ProtectedRoute><Layout><PublicGroups /></Layout></ProtectedRoute>} />
              <Route path="/groups/:id" element={<ProtectedRoute><Layout><GroupDetails /></Layout></ProtectedRoute>} />
              <Route path="/map" element={<ProtectedRoute><Layout><StudyMap /></Layout></ProtectedRoute>} />
              <Route path="/study-room/:id" element={<ProtectedRoute><Layout><StudyRoom /></Layout></ProtectedRoute>} />
              <Route path="/focus" element={<ProtectedRoute><Layout><PomodoroFocus /></Layout></ProtectedRoute>} />
              <Route path="/messages" element={<ProtectedRoute><Layout><Messages /></Layout></ProtectedRoute>} />
              <Route path="/support" element={<ProtectedRoute><Layout><Support /></Layout></ProtectedRoute>} />
              <Route path="/user/:id" element={<ProtectedRoute><Layout><UserProfile /></Layout></ProtectedRoute>} />
              <Route path="/profile" element={<ProtectedRoute><Layout><UserProfile /></Layout></ProtectedRoute>} />
              <Route path="/profile/edit" element={<ProtectedRoute><Layout><EditProfile /></Layout></ProtectedRoute>} />
              <Route path="/billing" element={<ProtectedRoute><Layout><Billing /></Layout></ProtectedRoute>} />
              <Route path="/pending" element={<PendingApproval />} />
              <Route path="/org-admin" element={<ProtectedRoute><Layout><OrgAdminDashboard /></Layout></ProtectedRoute>} />
              <Route path="/admin/user/:id/edit" element={<AdminRoute><Layout><EditProfile /></Layout></AdminRoute>} />
              <Route path="/admin" element={<AdminRoute><AdminPanel /></AdminRoute>} />
            </Routes>
          </BrowserRouter>
        </SocketProvider>
      </AuthProvider>
    </ThemeProvider>
    </GlobalErrorBoundary>
    </GoogleOAuthProvider>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Box, IconButton, Typography, TextField, CircularProgress, useTheme as useMuiTheme, Paper, Avatar, Button } from '@mui/material';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, X, Send, User, Bot, Loader2 } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { useTheme } from '../context/ThemeContext';
import { useAuth } from '../context/AuthContext';

export default function AIAssistantWidget() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { role: 'model', content: "Hi! I'm your AI StudyFriend. How can I help you today?" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const { theme } = useTheme();
  const { user } = useAuth();
  const navigate = useNavigate();
  const messagesEndRef = useRef(null);

  const isBasic = user?.subscription?.plan === 'basic';

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setLoading(true);

    try {
      // Send the entire conversation history along with the new prompt
      // We pass the previous history excluding the very first greeting if desired, or all.
      const historyPayload = messages.map(m => ({ role: m.role, content: m.content }));

      const res = await api.post('/ai/chat', { prompt: userMsg, history: historyPayload });

      setMessages(prev => [...prev, { role: 'model', content: res.data.text }]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'model', content: "I'm sorry, I'm having trouble connecting to my brain right now. Please tell the admin to check my API keys!" }]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <>
      <AnimatePresence>
        {isOpen && (
          <Box
            component={motion.div}
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            sx={{
              position: 'fixed',
              bottom: 164,
              right: 24,
              width: 380,
              height: 550,
              zIndex: 9999,
              display: 'flex',
              flexDirection: 'column',
              boxShadow: theme === 'dark' ? '0 20px 50px rgba(0,0,0,0.5)' : '0 20px 50px rgba(100,100,111,0.2)',
              borderRadius: 4,
              overflow: 'hidden',
              bgcolor: theme === 'dark' ? 'rgba(15, 23, 42, 0.85)' : 'rgba(255, 255, 255, 0.9)',
              backdropFilter: 'blur(20px)',
              WebkitBackdropFilter: 'blur(20px)',
              border: '1px solid',
              borderColor: theme === 'dark' ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)',
            }}
          >
            {/* Header */}
            <Box sx={{ 
              p: 2, 
              display: 'flex', 
              alignItems: 'center', 
              justifyContent: 'space-between',
              background: 'linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%)',
              color: 'white'
            }}>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
                <Avatar sx={{ bgcolor: 'rgba(255,255,255,0.2)', width: 36, height: 36 }}>
                  <Sparkles size={20} />
                </Avatar>
                <Box>
                  <Typography variant="subtitle1" fontWeight={700} lineHeight={1}>AI StudyFriend</Typography>
                  <Typography variant="caption" sx={{ opacity: 0.9 }}>Powered by Gemini</Typography>
                </Box>
              </Box>
              <IconButton size="small" onClick={() => setIsOpen(false)} sx={{ color: 'white', '&:hover': { bgcolor: 'rgba(255,255,255,0.1)' } }}>
                <X size={20} />
              </IconButton>
            </Box>

            {/* Chat Area */}
            <Box sx={{ flex: 1, p: 2, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 2, position: 'relative' }}>
              {isBasic && (
                <Box sx={{
                  position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
                  bgcolor: theme === 'dark' ? 'rgba(15,23,42,0.85)' : 'rgba(255,255,255,0.85)',
                  backdropFilter: 'blur(4px)',
                  zIndex: 2, display: 'flex', flexDirection: 'column', 
                  alignItems: 'center', justifyContent: 'center', p: 3, textAlign: 'center'
                }}>
                  <Avatar sx={{ bgcolor: 'rgba(99,102,241,0.1)', color: '#6366f1', width: 64, height: 64, mb: 2 }}>
                    <Sparkles size={32} />
                  </Avatar>
                  <Typography variant="h6" fontWeight={800} mb={1}>Pro Feature</Typography>
                  <Typography variant="body2" color="text.secondary" mb={3}>
                    Upgrade to Pro to unlock Gemini AI Study Tutor. Get instant help, summaries, and quizzes!
                  </Typography>
                  <Button 
                    onClick={() => { setIsOpen(false); navigate('/billing'); }}
                    sx={{
                      bgcolor: '#6366f1', color: 'white', px: 3, py: 1, borderRadius: '100px',
                      fontSize: '0.9rem', fontWeight: 700,
                      '&:hover': { bgcolor: '#4f46e5' }
                    }}
                  >
                    Upgrade Now
                  </Button>
                </Box>
              )}
              {messages.map((msg, idx) => (
                <Box key={idx} sx={{ display: 'flex', gap: 1.5, flexDirection: msg.role === 'user' ? 'row-reverse' : 'row' }}>
                  <Avatar sx={{ 
                    width: 32, height: 32, 
                    bgcolor: msg.role === 'user' ? 'primary.main' : 'secondary.main' 
                  }}>
                    {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                  </Avatar>

                  <Box sx={{ 
                    maxWidth: '80%', 
                    p: 1.5, 
                    borderRadius: 2,
                    bgcolor: msg.role === 'user' ? 'primary.main' : (theme === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.04)'),
                    color: msg.role === 'user' ? 'white' : 'text.primary',
                    borderTopRightRadius: msg.role === 'user' ? 4 : 16,
                    borderTopLeftRadius: msg.role === 'model' ? 4 : 16,
                  }}>
                    {msg.role === 'user' ? (
                       <Typography variant="body2">{msg.content}</Typography>
                    ) : (
                       <Box sx={{ 
                         '& p': { m: 0, mb: 1, fontSize: '0.875rem' }, 
                         '& p:last-child': { mb: 0 },
                         '& code': { bgcolor: theme === 'dark' ? 'rgba(0,0,0,0.3)' : 'rgba(0,0,0,0.05)', px: 0.5, borderRadius: 1, fontFamily: 'monospace' },
                         '& pre': { p: 1, borderRadius: 1, bgcolor: theme === 'dark' ? 'rgba(0,0,0,0.3)' : 'rgba(0,0,0,0.05)', overflowX: 'auto', '& code': { bgcolor: 'transparent', px: 0 } },
                         '& ul': { mt: 0, pl: 2, fontSize: '0.875rem' },
                         '& ol': { mt: 0, pl: 2, fontSize: '0.875rem' }
                       }}>
                         <ReactMarkdown>{msg.content || ''}</ReactMarkdown>
                       </Box>
                    )}
                  </Box>
                </Box>
              ))}

              {loading && (
                <Box sx={{ display: 'flex', gap: 1.5, alignItems: 'center' }}>
                  <Avatar sx={{ width: 32, height: 32, bgcolor: 'secondary.main' }}>
                    <Bot size={16} />
                  </Avatar>
                  <Box sx={{ p: 1.5, borderRadius: 2, bgcolor: theme === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.04)', display: 'flex', gap: 1 }}>
                     <motion.div animate={{ y: [0, -5, 0] }} transition={{ repeat: Infinity, duration: 0.6, delay: 0 }}><Box sx={{ width: 6, height: 6, borderRadius: '50%', bgcolor: 'text.secondary' }} /></motion.div>
                     <motion.div animate={{ y: [0, -5, 0] }} transition={{ repeat: Infinity, duration: 0.6, delay: 0.2 }}><Box sx={{ width: 6, height: 6, borderRadius: '50%', bgcolor: 'text.secondary' }} /></motion.div>
                     <motion.div animate={{ y: [0, -5, 0] }} transition={{ repeat: Infinity, duration: 0.6, delay: 0.4 }}><Box sx={{ width: 6, height: 6, borderRadius: '50%', bgcolor: 'text.secondary' }} /></motion.div>
                  </Box>
                </Box>
              )}
              <div ref={messagesEndRef} />
            </Box>

            {/* Input Area */}
            <Box sx={{ p: 2, borderTop: '1px solid', borderColor: 'divider', bgcolor: theme === 'dark' ? 'rgba(15,23,42,0.95)' : 'rgba(255,255,255,0.95)' }}>
              <TextField
                fullWidth
                multiline
                maxRows={3}
                placeholder="Ask your studyfriend..."
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                variant="outlined"
                size="small"
                disabled={loading || isBasic}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    borderRadius: 3,
                    pr: 1,
                    bgcolor: theme === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.02)',
                  }
                }}
                InputProps={{
                  endAdornment: (
                    <IconButton 
                      color="primary" 
                      onClick={handleSend} 
                      disabled={!input.trim() || loading}
                      sx={{ 
                        bgcolor: input.trim() ? 'primary.main' : 'transparent',
                        color: input.trim() ? 'white !important' : 'action.disabled',
                        '&:hover': { bgcolor: 'primary.dark' },
                        transition: 'all 0.2s',
                        width: 32, height: 32
                      }}
                    >
                      <Send size={16} style={{ marginLeft: 2 }} />
                    </IconButton>
                  ),
                }}
              />
            </Box>
          </Box>
        )}
      </AnimatePresence>

      {/* Floating Action Button */}
      <Box
        component={motion.div}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        sx={{
          position: 'fixed',
          bottom: 96,
          right: 24,
          zIndex: 9998,
        }}
      >
        <IconButton
          onClick={() => setIsOpen(!isOpen)}
          sx={{
            width: 56,
            height: 56,
            background: 'linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%)',
            color: 'white',
            boxShadow: '0 8px 24px rgba(139, 92, 246, 0.4)',
            '&:hover': {
              background: 'linear-gradient(135deg, #2563eb 0%, #7c3aed 100%)',
            }
          }}
        >
          {isOpen ? <X size={24} /> : <Sparkles size={24} />}
        </IconButton>
      </Box>
    </>
  );
}

