          <IconButton onClick={(e) => setAnchorElNotif(e.currentTarget)} sx={{ color: currentThemeMode === 'dark' ? 'rgba(255,255,255,0.7)' : 'text.secondary' }}>
            <Badge badgeContent={unreadCount} color="error" overlap="circular">
