import React, { useState, useEffect } from 'react';
import { Play, Pause, RotateCcw } from 'lucide-react';
import { Box, Paper, Typography, Button, IconButton, useTheme, Stack } from '@mui/material';

export default function PomodoroTimer() {
  const theme = useTheme();
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const [isBreak, setIsBreak] = useState(false);

  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft(time => time - 1);
      }, 1000);
    } else if (isActive && timeLeft === 0) {
      setIsActive(false);
      setIsBreak(!isBreak);
      setTimeLeft(isBreak ? 25 * 60 : 5 * 60);
      new Audio('/notification.mp3').play().catch(() => {});
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, isBreak]);

  const toggleTimer = () => setIsActive(!isActive);

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(isBreak ? 5 * 60 : 25 * 60);
  };

  const setMode = (breakMode) => {
    setIsBreak(breakMode);
    setIsActive(false);
    setTimeLeft(breakMode ? 5 * 60 : 25 * 60);
  };

  const minutes = Math.floor(timeLeft / 60);
  const seconds = timeLeft % 60;

  return (
    <Paper elevation={theme.palette.mode === 'dark' ? 4 : 1} sx={{ p: 4, borderRadius: 4, textAlign: 'center' }}>
      <Typography variant="h6" fontWeight={800} mb={3} color="text.primary">
        Pomodoro Timer
      </Typography>

      <Stack direction="row" justifyContent="center" gap={1} mb={4}>
        <Button 
          variant={!isBreak ? 'contained' : 'outlined'} 
          color="primary"
          onClick={() => setMode(false)}
          sx={{ borderRadius: 4, px: 3, fontWeight: 700 }}
        >
          Work
        </Button>
        <Button 
          variant={isBreak ? 'contained' : 'outlined'} 
          color="success"
          onClick={() => setMode(true)}
          sx={{ borderRadius: 4, px: 3, fontWeight: 700 }}
        >
          Break
        </Button>
      </Stack>

      <Typography variant="h2" fontWeight={900} fontFamily="monospace" color="text.primary" mb={4} sx={{ letterSpacing: 2 }}>
        {String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
      </Typography>

      <Stack direction="row" justifyContent="center" gap={2}>
        <IconButton
          onClick={toggleTimer}
          sx={{
            bgcolor: isActive ? theme.palette.warning.main : theme.palette.primary.main,
            color: 'white',
            width: 64,
            height: 64,
            '&:hover': { bgcolor: isActive ? theme.palette.warning.dark : theme.palette.primary.dark },
            boxShadow: theme.shadows[4]
          }}
        >
          {isActive ? <Pause size={32} /> : <Play size={32} style={{ marginLeft: 4 }} />}
        </IconButton>
        <IconButton
          onClick={resetTimer}
          sx={{
            bgcolor: 'background.default',
            color: 'text.secondary',
            width: 64,
            height: 64,
            border: 1,
            borderColor: 'divider',
            '&:hover': { bgcolor: 'action.hover' }
          }}
        >
          <RotateCcw size={28} />
        </IconButton>
      </Stack>
    </Paper>
  );
}

import { useState, useEffect } from 'react';
import { Calendar, Clock, Users, Video, MapPin, Trash2, LogIn, LogOut, ExternalLink, CalendarPlus, X, CheckCircle, Clock3, XCircle } from 'lucide-react';
import { format, addMinutes, differenceInSeconds } from 'date-fns';
import { Link } from 'react-router-dom';
import { Card, Box, Typography, Chip, Button, IconButton, useTheme, Avatar, AvatarGroup } from '@mui/material';
import { motion, AnimatePresence } from 'framer-motion';
import api from '../api/axios';
import toast from 'react-hot-toast';

export default function SessionCard({ session, currentUserId, onJoin, onLeave, onDelete }) {
  const theme = useTheme();
  const [isOpen, setIsOpen] = useState(false);
  const [countdown, setCountdown] = useState(null);

  const isHost = session.host?._id === currentUserId || session.host === currentUserId;
  const isParticipant = session.participants?.some(p => (p._id || p) === currentUserId);
  const isFull = session.participants?.length >= session.maxParticipants;
  const myRsvp = session.rsvps?.find(r => r.userId === currentUserId)?.status || 'PENDING';

  useEffect(() => {
    const timer = setInterval(() => {
      const start = new Date(session.scheduledAt);
      const now = new Date();
      if (start > now && differenceInSeconds(start, now) <= 900) { // 15 mins
        const m = Math.floor(differenceInSeconds(start, now) / 60);
        const s = differenceInSeconds(start, now) % 60;
        setCountdown(`${m}m ${s}s`);
      } else {
        setCountdown(null);
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [session.scheduledAt]);

  const handleRsvp = async (status) => {
    try {
      await api.post(`/sessions/${session._id}/rsvp`, { status });
      toast.success(`RSVP set to ${status}`);
    } catch {
      toast.error('Failed to RSVP');
    }
  };

  const getCalendarUrl = () => {
    const start = new Date(session.scheduledAt);
    const end = addMinutes(start, session.duration || 60);
    const formatDate = (date) => date.toISOString().replace(/-|:|\.\d\d\d/g, '');
    const url = new URL('https://calendar.google.com/calendar/render');
    url.searchParams.append('action', 'TEMPLATE');
    url.searchParams.append('text', session.title || 'StudyFriend Session');
    url.searchParams.append('dates', `${formatDate(start)}/${formatDate(end)}`);
    url.searchParams.append('details', session.description || 'Study session with connections');
    url.searchParams.append('location', session.isOnline ? (session.meetingLink || 'Online') : session.location);
    return url.toString();
  };

  return (
    <>
      <motion.div layoutId={`card-${session._id}`} onClick={() => !isOpen && setIsOpen(true)} style={{ height: '100%', cursor: 'pointer' }}>
        <Card variant="outlined" sx={{ 
          borderRadius: 4, display: 'flex', flexDirection: 'column', height: '100%', position: 'relative', overflow: 'hidden',
          transition: 'box-shadow 0.2s', '&:hover': { boxShadow: theme.shadows[6] }
        }}>
          {countdown && (
            <motion.div initial={{ y: -50 }} animate={{ y: 0 }} style={{ background: '#ef4444', color: 'white', padding: '4px 8px', textAlign: 'center', fontWeight: 800, fontSize: '0.8rem' }}>
              Starts in {countdown}!
            </motion.div>
          )}

          <Box sx={{ p: 3, flexGrow: 1 }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 2 }}>
              <Typography variant="h6" fontWeight={800} sx={{ lineHeight: 1.2 }}>{session.title}</Typography>
              <Chip label={session.subject} size="small" color="primary" variant="outlined" sx={{ fontWeight: 700 }} />
            </Box>

            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
              <Typography variant="body2" color="text.secondary" display="flex" alignItems="center" gap={1}>
                <Clock size={16} /> {format(new Date(session.scheduledAt), 'p')} · {session.duration}m
              </Typography>
              <Typography variant="body2" color="text.secondary" display="flex" alignItems="center" gap={1}>
                <Users size={16} /> {session.participants?.length}/{session.maxParticipants} part.
              </Typography>
              <Typography variant="body2" color="text.secondary" display="flex" alignItems="center" gap={1}>
                {session.isOnline ? <Video size={16} color={theme.palette.info.main} /> : <MapPin size={16} color={theme.palette.error.main} />}
                {session.isOnline ? 'Online' : session.location}
              </Typography>
            </Box>
          </Box>
        </Card>
      </motion.div>

      <AnimatePresence>
        {isOpen && (
          <Box sx={{ position: 'fixed', inset: 0, zIndex: 1300, display: 'flex', alignItems: 'center', justifyContent: 'center', p: 2 }}>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setIsOpen(false)} style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(8px)' }} />

            <motion.div layoutId={`card-${session._id}`} style={{ background: theme.palette.background.paper, borderRadius: '24px', width: '100%', maxWidth: 500, zIndex: 1301, overflow: 'hidden', boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)' }}>

              <Box sx={{ background: 'linear-gradient(135deg, #6366f1 0%, #ec4899 100%)', p: 4, position: 'relative', color: 'white' }}>
                <IconButton onClick={() => setIsOpen(false)} sx={{ position: 'absolute', top: 8, right: 8, color: 'white' }}><X /></IconButton>
                <Chip label={session.subject} size="small" sx={{ mb: 2, bgcolor: 'rgba(255,255,255,0.2)', color: 'white', fontWeight: 800 }} />
                <Typography variant="h4" fontWeight={900}>{session.title}</Typography>
                <Typography variant="subtitle1" fontWeight={600} mt={1}>{format(new Date(session.scheduledAt), 'PPPP')} at {format(new Date(session.scheduledAt), 'p')}</Typography>
              </Box>

              <Box sx={{ p: 4 }}>
                <Typography variant="body1" color="text.secondary" mb={4}>{session.description || 'No description provided.'}</Typography>

                <Box sx={{ display: 'flex', gap: 4, mb: 4 }}>
                  <Box>
                    <Typography variant="overline" fontWeight={800} color="text.secondary">Host</Typography>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 0.5 }}>
                      <Avatar src={session.host?.avatar} sx={{ width: 32, height: 32 }} />
                      <Typography variant="body2" fontWeight={700}>{session.host?.name}</Typography>
                    </Box>
                  </Box>
                  <Box>
                    <Typography variant="overline" fontWeight={800} color="text.secondary">Attendees</Typography>
                    <AvatarGroup max={4} sx={{ mt: 0.5, '& .MuiAvatar-root': { width: 32, height: 32 } }}>
                      {session.participants?.map(p => (
                        <Avatar key={p._id || p} src={p.avatar} />
                      ))}
                    </AvatarGroup>
                  </Box>
                </Box>

                {/* Smart RSVP UI */}
                {(isHost || isParticipant) && (
                  <Box sx={{ bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.03)', p: 2, borderRadius: 3, mb: 4, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <Typography variant="body2" fontWeight={800}>Your RSVP</Typography>
                    <Box sx={{ display: 'flex', gap: 1 }}>
                      <IconButton size="small" color={myRsvp === 'ATTENDING' ? 'success' : 'default'} onClick={() => handleRsvp('ATTENDING')}><CheckCircle size={20} /></IconButton>
                      <IconButton size="small" color={myRsvp === 'PENDING' ? 'warning' : 'default'} onClick={() => handleRsvp('PENDING')}><Clock3 size={20} /></IconButton>
                      <IconButton size="small" color={myRsvp === 'DECLINED' ? 'error' : 'default'} onClick={() => handleRsvp('DECLINED')}><XCircle size={20} /></IconButton>
                    </Box>
                  </Box>
                )}

                <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>
                  {!isHost && !isParticipant && !isFull && (
                    <Button variant="contained" fullWidth onClick={() => onJoin(session._id)} startIcon={<LogIn />} sx={{ fontWeight: 800 }}>Join Session</Button>
                  )}
                  {isParticipant && !isHost && (
                    <Button variant="outlined" color="error" fullWidth onClick={() => onLeave(session._id)} startIcon={<LogOut />} sx={{ fontWeight: 800 }}>Leave Session</Button>
                  )}
                  {(isHost || isParticipant) && session.isOnline && (
                    <Button component={Link} to={`/study-room/${session._id}`} variant="contained" color="success" fullWidth startIcon={<ExternalLink />} sx={{ fontWeight: 800 }}>
                      Enter Video Room
                    </Button>
                  )}
                  {(isHost || isParticipant) && (
                    <Button component="a" href={getCalendarUrl()} target="_blank" variant="outlined" color="info" fullWidth startIcon={<CalendarPlus />} sx={{ fontWeight: 800 }}>
                      Add to Calendar
                    </Button>
                  )}
                  {isHost && (
                    <Button color="error" fullWidth onClick={() => onDelete(session._id)} startIcon={<Trash2 />} sx={{ fontWeight: 800 }}>
                      Cancel Session
                    </Button>
                  )}
                </Box>
              </Box>

            </motion.div>
          </Box>
        )}
      </AnimatePresence>
    </>
  );
}

import React from 'react';
import { Box, useTheme, ButtonBase } from '@mui/material';
import { Link as RouterLink, useLocation } from 'react-router-dom';
import { BookOpen, Search, Users, Trophy, Calendar, Globe, MessageCircle, CreditCard, MapPin, Shield, Gamepad2, Joystick } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import Logo from './Logo';
import { io } from 'socket.io-client';
import toast from 'react-hot-toast';

const navLinks = [
  { to: '/dashboard', icon: BookOpen, label: 'Dashboard' },
  { to: '/browse', icon: Search, label: 'Browse' },
  { to: '/matches', icon: Users, label: 'Matches' },
  { to: '/gamification', icon: Gamepad2, label: 'Quests & XP' },
  { to: '/arcade', icon: Joystick, label: 'Recess Arcade' },
  { to: '/leaderboard', icon: Trophy, label: 'Leaderboard' },
  { to: '/sessions', icon: Calendar, label: 'Sessions' },
  { to: '/groups', icon: Globe, label: 'Squads' },
  { to: '/map', icon: MapPin, label: 'Nearby Map' },
  { to: '/messages', icon: MessageCircle, label: 'Messages' },
  { to: '/connections', icon: Users, label: 'Connections' },
  { to: '/billing', icon: CreditCard, label: 'Billing' },
];

export default function Sidebar({ mobileOpen = false, setMobileOpen = () => {} }) {
  const { user } = useAuth();
  const location = useLocation();
  const theme = useTheme();
  const isDark = theme.palette.mode === 'dark';
  const [unreadCount, setUnreadCount] = React.useState(0);

  React.useEffect(() => {
    if (!user) return;
    const socket = io(import.meta.env.VITE_API_URL?.replace('/api', '') || 'http://localhost:5001', {
      withCredentials: true
    });

    socket.emit('setup', user._id);

    socket.on('message_received', (newMessage) => {
      if (!location.pathname.startsWith('/messages')) {
        setUnreadCount(prev => prev + 1);
        toast(`New message from ${newMessage.sender?.name || 'someone'}`, {
          icon: '💬',
          style: { borderRadius: '100px', background: '#333', color: '#fff', fontWeight: 'bold' }
        });
      }
    });

    return () => {
      socket.off('message_received');
      socket.disconnect();
    };
  }, [user?._id, location.pathname]);

  const content = (
    <Box sx={{ 
      height: '100%', 
      display: 'flex', 
      flexDirection: 'column', 
      bgcolor: isDark ? 'rgba(15, 23, 42, 0.4)' : 'rgba(255, 255, 255, 0.5)', 
      backdropFilter: 'blur(16px)',
      border: '1px solid', 
      borderColor: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.05)',
      borderRadius: { xs: 0, md: '24px' },
      boxShadow: isDark ? '0 4px 30px rgba(0, 0, 0, 0.5)' : '0 4px 30px rgba(0, 0, 0, 0.03)',
      overflow: 'hidden'
    }}>

      {/* Brand Logo */}
      <Box sx={{ p: 3, pb: 4 }}>
        <Logo size={36} textColor={isDark ? 'white' : 'text.primary'} />
      </Box>

        {/* Navigation Links */}
        <Box sx={{ px: 2, flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column' }}>
          {(!user || user.role !== 'ORG_ADMIN' || user.isAdmin) && (
            <Box sx={{ px: 2, mb: 1, color: isDark ? 'rgba(255,255,255,0.4)' : 'text.secondary', fontWeight: 700, fontSize: '0.75rem', letterSpacing: '1px', textTransform: 'uppercase' }}>
              Menu
            </Box>
          )}

          {(!user || user.role !== 'ORG_ADMIN' || user.isAdmin) && navLinks.map(({ to, icon: Icon, label }) => {
            const isActive = location.pathname.startsWith(to);
          return (
            <ButtonBase
              component={RouterLink}
              to={to}
              key={to}
              onClick={() => setMobileOpen(false)}
              sx={{
                justifyContent: 'flex-start',
                width: '100%',
                mb: 0.5,
                p: 1.5,
                borderRadius: '12px',
                color: isActive ? '#6366f1' : (isDark ? 'rgba(255,255,255,0.6)' : 'text.secondary'),
                bgcolor: isActive ? (isDark ? 'rgba(99, 102, 241, 0.1)' : 'rgba(99, 102, 241, 0.05)') : 'transparent',
                '&:hover': {
                  bgcolor: isDark ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.02)',
                  color: isDark ? 'white' : 'text.primary'
                },
                transition: 'all 0.2s ease',
                display: 'flex',
                alignItems: 'center',
                gap: 2
              }}
            >
              <Box sx={{ position: 'relative' }}>
                <Icon size={20} strokeWidth={isActive ? 2.5 : 2} />
                {to === '/messages' && unreadCount > 0 && (
                  <Box sx={{
                    position: 'absolute', top: -5, right: -5,
                    bgcolor: '#ef4444', color: 'white', fontSize: '0.65rem',
                    fontWeight: 800, minWidth: 16, height: 16,
                    borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center'
                  }}>
                    {unreadCount > 9 ? '9+' : unreadCount}
                  </Box>
                )}
              </Box>
              <Box sx={{ fontWeight: isActive ? 700 : 500, fontSize: '0.95rem' }}>
                {label}
              </Box>
            </ButtonBase>
          );
        })}
        {(user?.role === 'ORG_ADMIN' || user?.isAdmin) && (
          <ButtonBase
            component={RouterLink}
            to="/org-admin"
            onClick={() => setMobileOpen(false)}
            sx={{
              justifyContent: 'flex-start', width: '100%', mb: 0.5, p: 1.5, borderRadius: '12px',
              color: location.pathname.startsWith('/org-admin') ? '#6366f1' : (isDark ? 'rgba(255,255,255,0.6)' : 'text.secondary'),
              bgcolor: location.pathname.startsWith('/org-admin') ? (isDark ? 'rgba(99, 102, 241, 0.1)' : 'rgba(99, 102, 241, 0.05)') : 'transparent',
              '&:hover': { bgcolor: isDark ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.02)', color: isDark ? 'white' : 'text.primary' },
              transition: 'all 0.2s ease', display: 'flex', alignItems: 'center', gap: 2
            }}
          >
            <Users size={20} strokeWidth={location.pathname.startsWith('/org-admin') ? 2.5 : 2} />
            <Box sx={{ fontWeight: location.pathname.startsWith('/org-admin') ? 700 : 500, fontSize: '0.95rem' }}>
              Org Admin
            </Box>
          </ButtonBase>
        )}

        {user?.isAdmin && (
          <ButtonBase
            component={RouterLink}
            to="/admin"
            onClick={() => setMobileOpen(false)}
            sx={{
              justifyContent: 'flex-start', width: '100%', mb: 0.5, p: 1.5, borderRadius: '12px',
              color: location.pathname.startsWith('/admin') ? '#ec4899' : (isDark ? 'rgba(255,255,255,0.6)' : 'text.secondary'),
              bgcolor: location.pathname.startsWith('/admin') ? (isDark ? 'rgba(236, 72, 153, 0.1)' : 'rgba(236, 72, 153, 0.05)') : 'transparent',
              '&:hover': { bgcolor: isDark ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.02)', color: isDark ? 'white' : 'text.primary' },
              transition: 'all 0.2s ease', display: 'flex', alignItems: 'center', gap: 2
            }}
          >
            <Shield size={20} strokeWidth={location.pathname.startsWith('/admin') ? 2.5 : 2} />
            <Box sx={{ fontWeight: location.pathname.startsWith('/admin') ? 700 : 500, fontSize: '0.95rem' }}>
              Super Admin
            </Box>
          </ButtonBase>
        )}
      </Box>

      {/* Upgrade Call to Action */}
      {(!user?.isAdmin && user?.role !== 'ORG_ADMIN') && (
        <Box sx={{ p: 3, m: 2, borderRadius: '16px', bgcolor: isDark ? 'rgba(99, 102, 241, 0.1)' : 'rgba(99, 102, 241, 0.05)', border: '1px solid', borderColor: isDark ? 'rgba(99, 102, 241, 0.2)' : 'rgba(99, 102, 241, 0.1)' }}>
          <Box sx={{ fontWeight: 700, fontSize: '0.875rem', color: '#6366f1', mb: 0.5 }}>Upgrade to Pro</Box>
          <Box sx={{ fontSize: '0.75rem', color: isDark ? 'rgba(255,255,255,0.6)' : 'text.secondary', display: 'block', mb: 2 }}>Unlock AI Tutor & unlimited Vaults.</Box>
          <ButtonBase component={RouterLink} to="/billing" sx={{ width: '100%', p: 1, borderRadius: '8px', bgcolor: '#6366f1', color: 'white', fontWeight: 600, fontSize: '0.875rem' }}>
            View Plans
          </ButtonBase>
        </Box>
      )}
    </Box>
  );

  if (mobileOpen) {
    return content;
  }

  return (
    <Box sx={{ display: { xs: 'none', md: 'block' }, width: 280, flexShrink: 0, height: 'calc(100vh - 32px)', position: 'sticky', top: 16 }}>
      {content}
    </Box>
  );
}

import { useState } from 'react';
import { Box, Typography, Avatar, Chip, Tooltip, CircularProgress, useTheme } from '@mui/material';
import { motion } from 'framer-motion';
import { Star, BookOpen, Activity } from 'lucide-react';
import api from '../api/axios';
import { useTheme as useCustomTheme } from '../context/ThemeContext';

export default function UserQuickPeek({ userId, children, placement = "top" }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const { theme } = useCustomTheme();
  const muiTheme = useTheme();

  const handleOpen = () => {
    if (!data && !loading && userId) {
      setLoading(true);
      api.get(`/users/${userId}/quick-peek`)
         .then(res => { setData(res.data); })
         .catch(err => { console.error(err); })
         .finally(() => { setLoading(false); });
    }
  };

  const Content = () => {
    if (loading || !data) {
      return (
        <Box sx={{ p: 3, display: 'flex', justifyContent: 'center', alignItems: 'center', minWidth: 200 }}>
          {loading ? <CircularProgress size={24} color="inherit" /> : <Typography variant="caption">Hover again...</Typography>}
        </Box>
      );
    }

    return (
      <Box sx={{ p: 2, minWidth: 220, display: 'flex', flexDirection: 'column', gap: 1.5 }}>
        {/* Header: Avatar, Name & Online Status */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
          <Box sx={{ position: 'relative' }}>
             <Avatar src={data.avatar} sx={{ width: 48, height: 48, border: '2px solid', borderColor: data.isOnline ? '#22c55e' : 'divider' }}>
               {data.name?.[0]}
             </Avatar>
             <Box sx={{ 
               position: 'absolute', bottom: 2, right: 2, width: 12, height: 12, borderRadius: '50%',
               bgcolor: data.isOnline ? '#22c55e' : '#94a3b8', border: '2px solid', borderColor: theme === 'dark' ? '#1e293b' : '#fff'
             }} />
          </Box>
          <Box>
            <Typography variant="body1" fontWeight={800} color={theme === 'dark' ? '#f8fafc' : '#0f172a'}>
              {data.name}
            </Typography>
            <Typography variant="caption" fontWeight={600} color={theme === 'dark' ? '#94a3b8' : '#64748b'} display="flex" alignItems="center" gap={0.5}>
              <Activity size={12} /> {data.isOnline ? 'Online Now' : 'Offline'}
            </Typography>
          </Box>
        </Box>

        {/* Stats Row */}
        <Box sx={{ display: 'flex', gap: 2, mt: 1 }}>
           <Typography variant="caption" fontWeight={700} display="flex" alignItems="center" gap={0.5} color={muiTheme.palette.warning.main}>
             <Star size={14} fill={muiTheme.palette.warning.main} /> {data.avgRating}
           </Typography>
           <Typography variant="caption" fontWeight={700} color="primary.main">
             Level {data.level}
           </Typography>
           {!data.isActive && (
              <Chip size="small" label="Banned" color="error" sx={{ height: 18, fontSize: '0.6rem', fontWeight: 800 }} />
           )}
        </Box>

        {/* Mutual Subjects */}
        {data.mutualSubjects && data.mutualSubjects.length > 0 && (
          <Box sx={{ mt: 1, p: 1.5, borderRadius: 2, bgcolor: theme === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.02)' }}>
            <Typography variant="caption" fontWeight={800} color="text.secondary" display="flex" alignItems="center" gap={0.5} mb={1}>
              <BookOpen size={12} /> Mutual Subjects
            </Typography>
            <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap' }}>
              {data.mutualSubjects.map((s, idx) => (
                <Chip key={idx} size="small" label={s} sx={{ fontSize: '0.65rem', height: 20, bgcolor: 'primary.main', color: '#fff', fontWeight: 600 }} />
              ))}
            </Box>
          </Box>
        )}
      </Box>
    );
  };

  return (
    <Tooltip
      placement={placement}
      onOpen={handleOpen}
      enterDelay={400}
      leaveDelay={200}
      componentsProps={{
        tooltip: {
          sx: {
            p: 0,
            bgcolor: theme === 'dark' ? 'rgba(15, 23, 42, 0.85)' : 'rgba(255, 255, 255, 0.85)',
            backdropFilter: 'blur(16px)',
            WebkitBackdropFilter: 'blur(16px)',
            border: '1px solid',
            borderColor: theme === 'dark' ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)',
            boxShadow: theme === 'dark' ? '0 10px 40px rgba(0,0,0,0.5)' : '0 10px 40px rgba(149,157,165,0.3)',
            borderRadius: 4,
            color: 'inherit'
          }
        }
      }}
      title={
        <motion.div
           initial={{ opacity: 0, y: 5 }}
           animate={{ opacity: 1, y: 0 }}
           transition={{ duration: 0.2 }}
        >
          <Content />
        </motion.div>
      }
    >
      <Box component="span" sx={{ display: 'inline-flex', cursor: 'pointer' }}>
        {children}
      </Box>
    </Tooltip>
  );
}

