source:
import React, { useState, useEffect } from 'react';
import { Box, Typography, Button, useTheme, IconButton } from '@mui/material';
import { motion, AnimatePresence } from 'framer-motion';
import { Wind, Play, Square, ChevronLeft } from 'lucide-react';
import toast from 'react-hot-toast';
import api from '../../api/axios';
import { useAuth } from '../../context/AuthContext';

const CYCLE_TIME = 19; // Inhale 4 + Hold 7 + Exhale 8
const GOAL_MINUTES = 2; // Required duration to earn XP 
const GOAL_SECONDS = GOAL_MINUTES * 60;

export default function ZenBreather({ onBack }) {
  const { user, setUser } = useAuth();
  const theme = useTheme();
  const isDark = theme.palette.mode === 'dark';

  const [isActive, setIsActive] = useState(false);
  const [sessionTime, setSessionTime] = useState(0); 
  const [phase, setPhase] = useState('Idle'); 
  const [xpAwarded, setXpAwarded] = useState(false);

  // Core Animation Loop Driver
  useEffect(() => {
    let interval = null;
    if (isActive) {
      interval = setInterval(() => {
        setSessionTime((prev) => {
          const next = prev + 1;
          const currentCycleSecond = next % CYCLE_TIME;

          if (currentCycleSecond < 4) {
            setPhase('Inhale');
          } else if (currentCycleSecond >= 4 && currentCycleSecond < 11) {
            setPhase('Hold');
          } else {
            setPhase('Exhale');
          }
          return next;
        });
      }, 1000);
    } else {
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [isActive]);

  // Check XP Condition Unlocked
  useEffect(() => {
    if (sessionTime >= GOAL_SECONDS && !xpAwarded) {
      handleCompleteSession();
    }
  }, [sessionTime, xpAwarded]);

  const handleCompleteSession = async () => {
    try {
      const res = await api.post('/gamification/reward', { xp: 15, game: 'ZenithBreather' });
      setUser({ ...user, xp: res.data.xp, level: res.data.level });
      toast.success('Inner peace achieved! +15 XP', { icon: '🧘' });
      setXpAwarded(true);
    } catch (err) {
      console.error('XP Sync fail');
    }
  };

  const toggleSession = () => {
    if (isActive) {
      setIsActive(false);
      setPhase('Paused');
    } else {
      setIsActive(true);
      if (phase === 'Idle' || phase === 'Paused') {
        setPhase('Inhale'); 
        if (sessionTime === 0 && xpAwarded) setXpAwarded(false); // Reset sequence
      }
    }
  };

  // UI States
  const getScale = () => {
    if (!isActive) return 1;
    if (phase === 'Inhale') return 1.6;
    if (phase === 'Hold') return 1.6;
    if (phase === 'Exhale') return 1;
    return 1;
  };

  return (
    <Box sx={{ width: '100%', maxWidth: 800, mx: 'auto', p: { xs: 3, md: 6 }, bgcolor: isDark ? 'transparent' : 'white', borderRadius: 4, display: 'flex', flexDirection: 'column', alignItems: 'center' }}>

      {/* HUD Header */}
      <Box sx={{ width: '100%', display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 8 }}>
         <IconButton onClick={onBack} sx={{ color: isDark ? 'white' : 'black' }}>
            <ChevronLeft size={28} />
         </IconButton>
         <Box sx={{ textAlign: 'center' }}>
            <Typography variant="caption" sx={{ letterSpacing: '2px', textTransform: 'uppercase', color: 'text.secondary', fontWeight: 700 }}>Clarity Routine</Typography>
            <Typography variant="h5" fontWeight={900} color={isDark ? 'white' : 'text.primary'} display="flex" alignItems="center" gap={1}>
              <Wind size={20} /> Zenith Breather
            </Typography>
         </Box>
         <Box sx={{ width: 40 }} /> {/* Spacer */}
      </Box>

      {/* Primary Visualizer Ring */}
      <Box sx={{ position: 'relative', width: 280, height: 280, display: 'flex', alignItems: 'center', justifyContent: 'center', mb: 8 }}>

        {/* Dynamic Expanding Aura */}
        <Box 
          component={motion.div}
          animate={{ scale: getScale() }}
          transition={{ duration: phase === 'Inhale' ? 4 : (phase === 'Exhale' ? 8 : 1), ease: 'easeInOut' }}
          sx={{ 
            position: 'absolute', width: '100%', height: '100%', 
            borderRadius: '50%', border: `2px solid ${isDark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.05)'}`, 
            bgcolor: isDark ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.01)',
            boxShadow: isActive ? (isDark ? '0 0 60px rgba(255,255,255,0.05)' : '0 0 60px rgba(0,0,0,0.03)') : 'none'
          }}
        />

        {/* Text Hub */}
        <Box sx={{ zIndex: 10, textAlign: 'center' }}>
          <AnimatePresence mode="popLayout">
            <motion.div key={phase} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }}>
               <Typography variant="h3" fontWeight={900} color={isDark ? 'white' : 'text.primary'} sx={{ letterSpacing: '-1px' }}>
                 {phase}
               </Typography>
            </motion.div>
          </AnimatePresence>
          {isActive && (
            <Typography variant="subtitle1" color="text.secondary" fontWeight={500} mt={1}>
              {Math.floor((GOAL_SECONDS - sessionTime) / 60)}:{(GOAL_SECONDS - sessionTime) % 60 < 10 ? '0' : ''}{(GOAL_SECONDS - sessionTime) % 60} Remaining
            </Typography>
          )}
        </Box>
      </Box>

      {/* Controls */}
      <Box sx={{ display: 'flex', gap: 3, alignItems: 'center' }}>
        <Button 
          variant="contained" 
          onClick={toggleSession}
          startIcon={isActive ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
          sx={{ 
            px: 6, py: 1.5, borderRadius: 10, fontWeight: 800, textTransform: 'none', fontSize: '1rem',
            bgcolor: isDark ? 'white' : 'black', color: isDark ? 'black' : 'white',
            '&:hover': { bgcolor: isDark ? 'rgba(255,255,255,0.8)' : 'rgba(0,0,0,0.8)' }
          }}
        >
          {isActive ? 'Pause Reflection' : (sessionTime > 0 ? 'Resume' : 'Begin 4-7-8 Sequence')}
        </Button>
      </Box>

      {xpAwarded && (
        <Typography variant="body2" color="#10b981" fontWeight={700} mt={4} component={motion.div} initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          +15 XP Awarded! You may continue breathing or return to the lobby.
        </Typography>
      )}
    </Box>
  );
}

import React from 'react';
import { Box, Typography, Chip, IconButton, useTheme } from '@mui/material';
import { Sparkles, ArrowUpRight, Target, Zap } from 'lucide-react';
import { motion } from 'framer-motion';

export default function AIInsightsWidget() {
  const theme = useTheme();
  const isDark = theme.palette.mode === 'dark';

  const insights = [
    { title: 'Peak Productivity', text: 'You are 24% more focused between 08:00 - 11:00 AM.', icon: <Zap size={16} />, color: '#22D3EE', bg: 'rgba(34,211,238,0.1)' },
    { title: 'Subject Synergy', text: 'Pairing Mathematics with Physics sessions improves retention by 15%.', icon: <Target size={16} />, color: '#8B5CF6', bg: 'rgba(139,92,246,0.1)' }
  ];

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
       <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Typography variant="h6" fontWeight={900} color={isDark ? "white" : "#0F172A"} display="flex" alignItems="center" gap={1.5}>
          <Sparkles size={20} color="#8B5CF6" /> AI Smart Insights
        </Typography>
        <Chip label="Live Sync" size="small" sx={{ bgcolor: 'rgba(139,92,246,0.1)', color: '#8B5CF6', fontWeight: 800, border: '1px solid rgba(139,92,246,0.2)' }} />
       </Box>

       <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3, flex: 1 }}>
         {insights.map((item, i) => (
           <motion.div key={i} whileHover={{ y: -5 }} transition={{ type: 'spring', stiffness: 300, damping: 20 }}>
              <Box sx={{ p: 3, borderRadius: '20px', bgcolor: isDark ? 'rgba(0,0,0,0.2)' : 'rgba(255,255,255,0.7)', border: '1px solid', borderColor: isDark ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)', display: 'flex', gap: 2, alignItems: 'flex-start', cursor: 'pointer', transition: 'all 0.2s', '&:hover': { borderColor: item.color, boxShadow: `0 10px 30px ${item.bg}` } }}>
                 <Box sx={{ bgcolor: item.bg, color: item.color, p: 1.5, borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                   {item.icon}
                 </Box>
                 <Box sx={{ flex: 1 }}>
                   <Typography variant="subtitle2" fontWeight={800} color={isDark ? "white" : "#0F172A"} mb={0.5}>{item.title}</Typography>
                   <Typography variant="body2" color={isDark ? "rgba(255,255,255,0.6)" : "rgba(15,23,42,0.6)"} lineHeight={1.5}>{item.text}</Typography>
                 </Box>
                 <IconButton size="small" sx={{ color: isDark ? 'rgba(255,255,255,0.3)' : 'rgba(15,23,42,0.3)' }}><ArrowUpRight size={16} /></IconButton>
              </Box>
           </motion.div>
         ))}
       </Box>
    </Box>
  );
}

import React, { useEffect, useState } from 'react';
import { Box, Typography, Tooltip, Button, useTheme } from '@mui/material';
import { Network, Lock } from 'lucide-react';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import api from '../../api/axios';
import { useAuth } from '../../context/AuthContext';

export default function ActivityHeatmap() {
  const theme = useTheme();
  const isDark = theme.palette.mode === 'dark';
  const { user } = useAuth();
  const navigate = useNavigate();
  const [activityData, setActivityData] = useState([]);

  const isBasic = user?.subscription?.plan === 'basic';

  useEffect(() => {
    if (user?._id) {
      api.get(`/activity/heatmap/${user._id}`)
        .then(res => setActivityData(res.data))
        .catch(() => {});
    }
  }, [user]);

  // Generate last 365 days
  const today = new Date();
  const startDate = new Date(today);
  startDate.setDate(today.getDate() - 364);

  // Group timestamps by YYYY-MM-DD
  const countsByDate = activityData.reduce((acc, timestamp) => {
    const d = new Date(timestamp).toISOString().split('T')[0];
    acc[d] = (acc[d] || 0) + 1;
    return acc;
  }, {});

  const weeks = [];
  let currentWeek = [];

  // Align start to the correct day of the week
  const startDayPadding = startDate.getDay();
  for (let i = 0; i < startDayPadding; i++) {
    currentWeek.push(null);
  }

  for (let d = new Date(startDate); d <= today; d.setDate(d.getDate() + 1)) {
    const dateStr = d.toISOString().split('T')[0];
    currentWeek.push({
      date: dateStr,
      count: countsByDate[dateStr] || 0
    });

    if (currentWeek.length === 7) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
  }

  // Push remaining days in final week
  if (currentWeek.length > 0) {
    while (currentWeek.length < 7) currentWeek.push(null);
    weeks.push(currentWeek);
  }

  const getColor = (count) => {
    if (count === 0) return 'rgba(255,255,255,0.05)';
    if (count < 3) return 'rgba(16, 185, 129, 0.4)';
    if (count < 6) return 'rgba(16, 185, 129, 0.7)';
    return 'rgba(16, 185, 129, 1)';
  };

  return (
    <Box sx={{ 
      p: 4, 
      bgcolor: isDark ? 'rgba(15, 23, 42, 0.4)' : 'rgba(255, 255, 255, 0.5)', 
      backdropFilter: 'blur(16px)',
      border: '1px solid',
      borderColor: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.05)', 
      borderRadius: '24px',
      boxShadow: isDark ? '0 10px 30px rgba(0, 0, 0, 0.5)' : '0 10px 30px rgba(0, 0, 0, 0.05)', 
      position: 'relative', 
      overflow: 'hidden'
    }}>

      {isBasic && (
        <Box sx={{
          position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
          bgcolor: 'rgba(15,23,42,0.85)', backdropFilter: 'blur(5px)',
          zIndex: 10, display: 'flex', flexDirection: 'column', 
          alignItems: 'center', justifyContent: 'center', p: 3, textAlign: 'center'
        }}>
          <Box sx={{ width: 64, height: 64, borderRadius: '20px', bgcolor: 'rgba(99,102,241,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', mb: 3 }}>
            <Lock size={32} color="#6366f1" />
          </Box>
          <Typography variant="h5" fontWeight={800} color="white" mb={1}>Advanced Heatmaps locked</Typography>
          <Typography variant="body1" color="rgba(255,255,255,0.6)" mb={4} maxWidth={400}>
            Upgrade to Pro to unlock detailed study velocity heatmaps and sync your GitHub activity seamlessly!
          </Typography>
          <Button 
            variant="contained"
            onClick={() => navigate('/billing')}
            sx={{ bgcolor: '#6366f1', color: 'white', px: 4, py: 1.5, borderRadius: '100px', fontWeight: 800, '&:hover': { bgcolor: '#4f46e5' } }}
          >
            Unlock Heatmaps
          </Button>
        </Box>
      )}
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 4 }}>
        <Box sx={{ width: 40, height: 40, borderRadius: '12px', bgcolor: 'rgba(16, 185, 129, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Network size={20} color="#10b981" />
        </Box>
        <Typography variant="h6" fontWeight="800" color="white">Velocity Heatmap</Typography>
      </Box>

      <Box sx={{ overflowX: 'auto', pb: 2 }}>
        <Box sx={{ display: 'flex', gap: '4px', minWidth: '800px' }}>
          {weeks.map((week, wIdx) => (
            <Box key={wIdx} sx={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
              {week.map((day, dIdx) => {
                if (!day) return <Box key={`empty-${wIdx}-${dIdx}`} sx={{ width: 14, height: 14, borderRadius: '4px' }} />;

                return (
                  <Tooltip key={day.date} title={`${day.count} activities on ${day.date}`} placement="top" arrow>
                    <motion.div
                      whileHover={{ scale: 1.2, zIndex: 10 }}
                      style={{ 
                        width: 14, height: 14, borderRadius: '4px', cursor: 'pointer',
                        backgroundColor: getColor(day.count)
                      }}
                    />
                  </Tooltip>
                );
              })}
            </Box>
          ))}
        </Box>
      </Box>
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: 1, mt: 2, mb: 1 }}>
        <Typography variant="caption" color="rgba(255,255,255,0.5)">Less</Typography>
        <Box sx={{ width: 12, height: 12, borderRadius: '2px', bgcolor: 'rgba(255,255,255,0.05)' }} />
        <Box sx={{ width: 12, height: 12, borderRadius: '2px', bgcolor: 'rgba(16, 185, 129, 0.4)' }} />
        <Box sx={{ width: 12, height: 12, borderRadius: '2px', bgcolor: 'rgba(16, 185, 129, 0.7)' }} />
