import api from '../../api/axios';
import ReactMarkdown from 'react-markdown';
import { useAuth } from '../../context/AuthContext';

export default function SquadChat({ groupId, subject, name }) {
  const [messages, setMessages] = useState([{
    id: 'msg-1',
    sender: 'ai',
    text: `Hi squad! I'm Gemini, your AI Study Tutor. Ask me to explain concepts, summarize notes, or generate quizzes about ${subject}!`
  }]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);
  const { user } = useAuth();
  const navigate = useNavigate();

  const isBasic = user?.subscription?.plan === 'basic';

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg = { id: Date.now().toString(), sender: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const res = await api.post('/ai/squad-tutor', {
        prompt: userMsg.text,
        squadName: name,
        subject: subject
      });
      setMessages(prev => [...prev, { id: Date.now().toString() + 'ai', sender: 'ai', text: res.data.text }]);
    } catch (err) {
      setMessages(prev => [...prev, { id: Date.now().toString() + 'err', sender: 'ai', text: 'Sorry, I failed to process that request. The neural link might be down.' }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ height: '600px', display: 'flex', flexDirection: 'column', bgcolor: '#020617', borderRadius: '32px', border: '1px solid rgba(255,255,255,0.05)', overflow: 'hidden' }}>

      <Box sx={{ p: 3, borderBottom: '1px solid rgba(255,255,255,0.05)', display: 'flex', alignItems: 'center', gap: 2, bgcolor: 'rgba(255,255,255,0.02)' }}>
        <Box sx={{ width: 40, height: 40, borderRadius: '12px', bgcolor: 'rgba(99, 102, 241, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Sparkles size={20} color="#818cf8" />
        </Box>
        <Box>
          <Typography variant="subtitle1" fontWeight="800" color="white">Gemini Tutor</Typography>
          <Typography variant="caption" color="rgba(255,255,255,0.5)">Always active in {name}</Typography>
        </Box>
      </Box>

      <Box sx={{ flex: 1, overflowY: 'auto', p: 3, display: 'flex', flexDirection: 'column', gap: 3, position: 'relative' }}>
        {isBasic && (
          <Box sx={{
            position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
            bgcolor: 'rgba(2,6,23,0.85)', backdropFilter: 'blur(4px)',
            zIndex: 10, display: 'flex', flexDirection: 'column', 
            alignItems: 'center', justifyContent: 'center', p: 4, textAlign: 'center'
          }}>
            <Box sx={{ width: 64, height: 64, borderRadius: '20px', bgcolor: 'rgba(99,102,241,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', mb: 3 }}>
              <Sparkles size={32} color="#818cf8" />
            </Box>
            <Typography variant="h5" fontWeight={800} color="white" mb={1}>Squad AI Tutor Locked</Typography>
            <Typography variant="body1" color="rgba(255,255,255,0.6)" mb={4} maxWidth={300}>
              Upgrade to Pro to chat with Gemini inside your squads for instant concept explanations and quizzes!
            </Typography>
            <Button 
              onClick={() => navigate('/billing')}
              sx={{ bgcolor: '#8b5cf6', color: 'white', px: 4, py: 1.5, borderRadius: '100px', fontWeight: 800, '&:hover': { bgcolor: '#7c3aed' } }}
            >
              Unlock Priority AI
            </Button>
          </Box>
        )}
        <AnimatePresence>
          {messages.map((msg) => {
            const isUser = msg.sender === 'user';
            return (
              <motion.div
                key={msg.id}
                initial={{ opacity: 0, y: 10, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                layout
                style={{ 
                  display: 'flex', 
                  alignSelf: isUser ? 'flex-end' : 'flex-start', 
                  maxWidth: '85%', 
                  gap: '12px',
                  flexDirection: isUser ? 'row-reverse' : 'row'
                }}
              >
                {!isUser && (
                  <Box sx={{ width: 32, height: 32, borderRadius: '10px', bgcolor: 'rgba(59, 130, 246, 0.2)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, mt: 1 }}>
                    <Bot size={18} color="#60a5fa" />
                  </Box>
                )}
                <Box sx={{ 
                  p: 2.5, 
                  bgcolor: isUser ? '#6366f1' : 'rgba(255,255,255,0.05)', 
                  color: 'white', 
                  borderRadius: '24px', 
                  borderTopRightRadius: isUser ? 4 : 24, 
                  borderTopLeftRadius: !isUser ? 4 : 24,
                  border: isUser ? 'none' : '1px solid rgba(255,255,255,0.1)',
                  boxShadow: isUser ? '0 10px 20px -10px rgba(99, 102, 241, 0.5)' : 'none'
                }}>
                  <div className="prose prose-sm dark:prose-invert max-w-none">
                   <ReactMarkdown components={{ p: ({node, ...props}) => <Typography variant="body2" sx={{ lineHeight: 1.6 }} {...props} /> }}>
                     {msg.text || ''}
                   </ReactMarkdown>
                  </div>
                </Box>
              </motion.div>
            );
          })}
        </AnimatePresence>

        {loading && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ display: 'flex', alignSelf: 'flex-start', gap: '12px' }}>
            <Box sx={{ width: 32, height: 32, borderRadius: '10px', bgcolor: 'rgba(59, 130, 246, 0.2)', display: 'flex', alignItems: 'center', justifyContent: 'center', mt: 1 }}>
              <Bot size={18} color="#60a5fa" />
            </Box>
            <Box sx={{ p: 2, borderRadius: '24px', borderTopLeftRadius: 4, bgcolor: 'rgba(255,255,255,0.05)', display: 'flex', alignItems: 'center' }}>
              <CircularProgress size={20} thickness={5} sx={{ color: '#8b5cf6' }} />
            </Box>
          </motion.div>
        )}
        <div ref={messagesEndRef} />
      </Box>

      <Box component="form" onSubmit={handleSend} sx={{ p: 2, display: 'flex', gap: 1, bgcolor: 'rgba(255,255,255,0.02)', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
        <TextField 
          fullWidth size="small" 
          placeholder="Ask Gemini something..." 
          value={input} onChange={e => setInput(e.target.value)} 
          autoComplete="off"
          disabled={loading || isBasic}
          sx={{ 
            input: { color: 'white' }, 
            '& .MuiOutlinedInput-root': {
              bgcolor: 'rgba(255,255,255,0.05)',
              borderRadius: '100px',
              '& fieldset': { borderColor: 'transparent' },
              '&:hover fieldset': { borderColor: 'rgba(255,255,255,0.1)' },
              '&.Mui-focused fieldset': { borderColor: '#818cf8' },
            }
          }} 
        />
        <Button 
          type="submit" variant="contained" 
          disabled={loading || !input.trim() || isBasic}
          sx={{ 
            borderRadius: '100px', minWidth: '48px', width: '48px', height: '48px', p: 0,
            bgcolor: '#8b5cf6', '&:hover': { bgcolor: '#7c3aed' },
            '&.Mui-disabled': { bgcolor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.3)' }
          }}
        >
          <Send size={18} />
        </Button>
      </Box>
    </Box>
  );
}

import React, { useState } from 'react';
import { Box, Typography, Button, TextField, IconButton } from '@mui/material';
import { Plus, Trash, CheckCircle2, GripVertical } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import api from "../../api/axios";
import toast from 'react-hot-toast';

export default function SquadKanban({ groupId, initialTasks = [] }) {
  const [tasks, setTasks] = useState(initialTasks);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [draggedTaskId, setDraggedTaskId] = useState(null);

  const columns = ['To Do', 'Doing', 'Done'];

  const saveTasks = async (newTasks) => {
    try {
      await api.put(`/groups/${groupId}/kanban`, { kanbanTasks: newTasks });
    } catch {
      toast.error('Failed to save tasks');
    }
  };

  const addTask = () => {
    if (!newTaskTitle.trim()) return;
    const newTask = { id: Date.now().toString(), title: newTaskTitle, status: 'To Do' };
    const updated = [...tasks, newTask];
    setTasks(updated);
    setNewTaskTitle('');
    saveTasks(updated);
  };

  const deleteTask = (taskId) => {
    const updated = tasks.filter(t => t.id !== taskId);
    setTasks(updated);
    saveTasks(updated);
  };

  const handleDragStart = (e, taskId) => {
    setDraggedTaskId(taskId);
    e.dataTransfer.effectAllowed = 'move';
    // Make it look clean while dragging
    e.target.style.opacity = '0.5';
  };

  const handleDragEnd = (e) => {
    e.target.style.opacity = '1';
    setDraggedTaskId(null);
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e, targetStatus) => {
    e.preventDefault();
    if (!draggedTaskId) return;

    const updated = tasks.map(t => {
      if (t.id === draggedTaskId) {
        return { ...t, status: targetStatus };
      }
      return t;
    });

    setTasks(updated);
    saveTasks(updated);
    setDraggedTaskId(null);
  };

  return (
    <Box sx={{ p: { xs: 2, md: 4 }, bgcolor: '#020617', minHeight: '600px', borderRadius: '32px' }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 4 }}>
        <Typography variant="h5" fontWeight="900" color="white">Kanban Board</Typography>
        <Box sx={{ display: 'flex', gap: 2, width: { xs: '100%', md: '400px' } }}>
          <TextField 
            size="small" fullWidth placeholder="What needs to be done?" 
            value={newTaskTitle} 
            onChange={e => setNewTaskTitle(e.target.value)} 
            onKeyPress={e => e.key === 'Enter' && addTask()}
            sx={{ input: { color: 'white' }, '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(255,255,255,0.2)', borderRadius: '100px' } }}
          />
          <Button variant="contained" onClick={addTask} sx={{ borderRadius: '100px', minWidth: '40px', p: 0, bgcolor: '#6366f1', '&:hover': { bgcolor: '#4f46e5' } }}>
            <Plus size={20} />
          </Button>
        </Box>
      </Box>

      <Box sx={{ display: 'flex', gap: 3, overflowX: 'auto', pb: 2, minHeight: '500px' }}>
        {columns.map(col => {
          const colTasks = tasks.filter(t => t.status === col);
          const isDone = col === 'Done';

          return (
            <Box 
              key={col} 
              onDragOver={handleDragOver}
              onDrop={(e) => handleDrop(e, col)}
              sx={{ 
                width: 320, flexShrink: 0, p: 2, 
                bgcolor: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)', 
                borderRadius: '24px', display: 'flex', flexDirection: 'column' 
              }}
            >
              <Typography variant="h6" fontWeight="800" color="white" mb={3} display="flex" alignItems="center" gap={1}>
                {isDone && <CheckCircle2 size={18} color="#10b981" />}
                {col} <Typography component="span" sx={{ bgcolor: 'rgba(255,255,255,0.1)', px: 1.5, py: 0.5, borderRadius: '100px', fontSize: '0.8rem' }}>{colTasks.length}</Typography>
              </Typography>

              <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'column', gap: 2 }}>
                <AnimatePresence>
                  {colTasks.map(task => (
                    <motion.div
                      key={task.id}
                      layout
                      initial={{ opacity: 0, y: 20 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, scale: 0.9 }}
                      whileHover={{ scale: 1.02 }}
                      whileTap={{ scale: 0.98 }}
                    >
                      <Box
                        draggable
                        onDragStart={(e) => handleDragStart(e, task.id)}
                        onDragEnd={handleDragEnd}
                        sx={{ 
                          p: 2.5, bgcolor: isDone ? 'rgba(16, 185, 129, 0.05)' : 'rgba(255,255,255,0.05)', 
                          border: `1px solid ${isDone ? 'rgba(16, 185, 129, 0.2)' : 'rgba(255,255,255,0.1)'}`,
                          borderRadius: '16px', cursor: 'grab', display: 'flex', alignItems: 'center', gap: 2,
                          '&:active': { cursor: 'grabbing' } 
                        }}
                      >
                        <GripVertical size={16} color="rgba(255,255,255,0.3)" style={{ cursor: 'grab' }} />
                        <Typography fontWeight="600" color={isDone ? 'rgba(255,255,255,0.5)' : 'white'} sx={{ flexGrow: 1, textDecoration: isDone ? 'line-through' : 'none' }}>
                          {task.title}
                        </Typography>
                        <IconButton size="small" onClick={() => deleteTask(task.id)} sx={{ color: 'rgba(255,255,255,0.3)', '&:hover': { color: '#ef4444', bgcolor: 'rgba(239, 68, 68, 0.1)' } }}>
                          <Trash size={16} />
                        </IconButton>
                      </Box>
                    </motion.div>
                  ))}
                </AnimatePresence>

                {colTasks.length === 0 && (
                  <Box sx={{ p: 4, textAlign: 'center', border: '1px dashed rgba(255,255,255,0.1)', borderRadius: '16px' }}>
                    <Typography color="rgba(255,255,255,0.3)" variant="body2">Drop tasks here</Typography>
                  </Box>
                )}
              </Box>
            </Box>
          );
        })}
      </Box>
    </Box>
  );
}

import React, { useState, useRef } from 'react';
import { Box, Typography, Button, TextField, Paper, Select, MenuItem, Grid, IconButton, Dialog, DialogTitle, DialogContent, DialogActions, Fab, Tooltip, CircularProgress } from '@mui/material';
import { Upload, FileText, Link as LinkIcon, Download, Loader2, Folder, Sparkles, X, Send, Bot } from 'lucide-react';
import { motion, useMotionValue, useSpring, useTransform, AnimatePresence } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import api from "../../api/axios";
import toast from 'react-hot-toast';



const staggerContainer = { hidden: { opacity: 0 }, visible: { opacity: 1, transition: { staggerChildren: 0.1 } } };
const fadeUpSpring = { hidden: { opacity: 0, y: 30 }, visible: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 100, damping: 15 } } };

export default function SquadVault({ groupId, initialResources = [] }) {
  const [resources, setResources] = useState(initialResources);
  const [form, setForm] = useState({ title: '', url: '', type: 'link' });
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef(null);

  // AI Tutor State
  const [isTutorOpen, setIsTutorOpen] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [chatHistory, setChatHistory] = useState([
    { role: 'model', content: "Hi! I'm your squad's AI Tutor. Ask me any questions about the subjects you're currently studying!" }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const chatBottomRef = useRef(null);

  const handleAskTutor = async () => {
    if (!prompt.trim()) return;
    const userMsg = prompt.trim();
    setPrompt('');
    setChatHistory(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsTyping(true);

    setTimeout(() => chatBottomRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);

    try {
      const res = await api.post('/ai/squad-tutor', {
        prompt: userMsg,
        squadName: "Your Squad",
        subject: "your shared resources"
      });
      setChatHistory(prev => [...prev, { role: 'model', content: res.data.text }]);
    } catch (err) {
      toast.error('AI Tutor failed to connect!');
    } finally {
      setIsTyping(false);
      setTimeout(() => chatBottomRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);
    }
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsUploading(true);
    const formData = new FormData();
    formData.append('file', file);

    try {
      // 1. Upload to backend multer `/api/upload`
      const uploadRes = await api.post('/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      const wsUrl = import.meta.env.VITE_API_URL?.replace('/api', '') || 'http://localhost:5001';
      const fileUrl = `${wsUrl}${uploadRes.data.url}`; // Ensure absolute backend URL for now

      // 2. Save resource to Group
      const res = await api.post(`/groups/${groupId}/resources`, {
        id: Date.now().toString(),
        title: uploadRes.data.name,
        url: fileUrl,
        type: file.type.includes('pdf') ? 'pdf' : 'other'
      });
      setResources([...resources, res.data]);
      toast.success('File uploaded successfully!');
    } catch (err) {
      toast.error('Failed to upload file');
    } finally {
      setIsUploading(false);
      e.target.value = null; // reset
    }
  };

  const addLink = async (e) => {
    e.preventDefault();
    if (!form.title || !form.url) return;
    try {
      const res = await api.post(`/groups/${groupId}/resources`, {
        id: Date.now().toString(),
        ...form
      });
      setResources([...resources, res.data]);
      setForm({ title: '', url: '', type: 'link' });
      toast.success('Link shared!');
    } catch (err) {
      toast.error('Failed to share link');
    }
  };

  return (
    <Box sx={{ p: { xs: 2, md: 4 }, bgcolor: '#020617', minHeight: '600px', borderRadius: '32px' }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 4 }}>
        <Typography variant="h5" fontWeight="900" color="white">Resource Vault</Typography>
        <Button 
          variant="contained" 
          disabled={isUploading}
          onClick={() => fileInputRef.current?.click()}
          startIcon={isUploading ? <Loader2 className="animate-spin" size={18} /> : <Upload size={18} />}
          sx={{ borderRadius: '100px', px: 3, bgcolor: '#6366f1', '&:hover': { bgcolor: '#4f46e5' }, textTransform: 'none', fontWeight: 800 }}
        >
          {isUploading ? 'Uploading...' : 'Upload File'}
        </Button>
        <input type="file" hidden ref={fileInputRef} onChange={handleFileUpload} />
      </Box>

      {/* Link Sharing Bar */}
      <Box component="form" onSubmit={addLink} sx={{ display: 'flex', gap: 2, mb: 6, bgcolor: 'rgba(255,255,255,0.03)', p: 2, borderRadius: '24px', border: '1px solid rgba(255,255,255,0.1)' }}>
        <Select size="small" value={form.type} onChange={e => setForm({ ...form, type: e.target.value })} sx={{ width: 140, color: 'white', '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(255,255,255,0.2)' } }}>
          <MenuItem value="link">Web Link</MenuItem>
          <MenuItem value="pdf">External PDF</MenuItem>
          <MenuItem value="other">Other Link</MenuItem>
        </Select>
        <TextField size="small" placeholder="Resource Title" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} required sx={{ input: { color: 'white' }, '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(255,255,255,0.2)' } }} />
        <TextField size="small" fullWidth placeholder="URL (https://...)" value={form.url} onChange={e => setForm({ ...form, url: e.target.value })} required sx={{ input: { color: 'white' }, '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(255,255,255,0.2)' } }} />
        <Button type="submit" variant="outlined" startIcon={<LinkIcon size={18} />} sx={{ borderRadius: '100px', color: 'white', borderColor: 'rgba(255,255,255,0.3)', textTransform: 'none', fontWeight: 700 }}>Save Link</Button>
      </Box>

      {/* Resources Grid */}
      <motion.div initial="hidden" animate="visible" variants={staggerContainer}>
        <Grid container spacing={3}>
          {resources.length === 0 ? (
            <Grid item xs={12}>
              <Box sx={{ py: 10, textAlign: 'center', border: '1px dashed rgba(255,255,255,0.2)', borderRadius: '32px' }}>
                <Folder size={48} color="rgba(255,255,255,0.2)" style={{ margin: '0 auto 16px' }} />
                <Typography color="rgba(255,255,255,0.5)">The Vault is empty. Upload PDFs or share links securely.</Typography>
              </Box>
            </Grid>
          ) : (
            resources.map((r, i) => (
              <Grid item xs={12} sm={6} md={4} key={i}>
                <motion.div variants={fadeUpSpring} style={{ height: '100%' }}>
                  <Box sx={{ 
                    p: 3, display: 'flex', flexDirection: 'column', height: '100%',
                    bgcolor: 'background.paper', borderRadius: '16px',
                    border: '1px solid', borderColor: 'divider',
                    boxShadow: '0 4px 12px rgba(0,0,0,0.05)'
                  }}>
                    <Box sx={{ width: 48, height: 48, borderRadius: '12px', bgcolor: r.type === 'link' ? 'primary.light' : 'error.light', display: 'flex', alignItems: 'center', justifyContent: 'center', mb: 2 }}>
                      {r.type === 'link' ? <LinkIcon size={24} color="#1e40af" /> : <FileText size={24} color="#991b1b" />}
                    </Box>
                    <Typography fontWeight="800" color="text.primary" sx={{ mb: 1, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{r.title}</Typography>
                    <Typography variant="body2" color="text.secondary" mb={3}>{new Date(r.createdAt || Date.now()).toLocaleDateString()}</Typography>
                    <Box sx={{ mt: 'auto' }}>
                      <Button component="a" href={r.url} target="_blank" rel="noopener noreferrer" fullWidth variant="outlined" sx={{ borderRadius: '100px', textTransform: 'none', fontWeight: 700 }} endIcon={<Download size={16} />}>
                        Access
                      </Button>
                    </Box>
                  </Box>
                </motion.div>
              </Grid>
            ))
          )}
        </Grid>
      </motion.div>

      {/* Floating Action Button */}
      <Tooltip title="Ask AI Tutor" placement="left">
        <Fab 
          color="primary" 
          aria-label="ai tutor"
          onClick={() => setIsTutorOpen(true)}
          sx={{ 
            position: 'fixed', 
            bottom: 32, 
            right: 32, 
            bgcolor: '#6366f1', 
            '&:hover': { bgcolor: '#4f46e5' },
            boxShadow: '0 8px 32px rgba(99, 102, 241, 0.4)'
          }}
        >
          <Sparkles />
        </Fab>
      </Tooltip>

      {/* AI Tutor Dialog */}
      <Dialog 
        open={isTutorOpen} 
        onClose={() => setIsTutorOpen(false)}
        maxWidth="sm"
        fullWidth
        PaperProps={{
          sx: {
            bgcolor: '#0f172a',
            backgroundImage: 'none',
            borderRadius: '24px',
            border: '1px solid rgba(255,255,255,0.1)',
            overflow: 'hidden'
          }
        }}
      >
        <DialogTitle sx={{ display: 'flex', alignItems: 'center', gap: 2, p: 3, borderBottom: '1px solid rgba(255,255,255,0.05)', bgcolor: 'rgba(255,255,255,0.02)' }}>
          <Box sx={{ width: 40, height: 40, borderRadius: '12px', bgcolor: 'rgba(99, 102, 241, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Bot size={24} color="#818cf8" />
          </Box>
          <Box flex={1}>
            <Typography variant="h6" fontWeight="800" color="white" lineHeight={1.2}>Squad AI Tutor</Typography>
            <Typography variant="caption" color="text.secondary">Powered by Gemini Pro</Typography>
          </Box>
          <IconButton onClick={() => setIsTutorOpen(false)} sx={{ color: 'rgba(255,255,255,0.5)' }}>
            <X />
          </IconButton>
        </DialogTitle>
        <DialogContent sx={{ p: 0, height: '400px', display: 'flex', flexDirection: 'column', bgcolor: '#020617' }}>
          <Box sx={{ flex: 1, overflowY: 'auto', p: 3, display: 'flex', flexDirection: 'column', gap: 2 }}>
            {chatHistory.map((msg, idx) => (
