          <IconButton 
            onClick={handleAskTutor} 
            disabled={!prompt.trim() || isTyping}
            sx={{ bgcolor: '#6366f1', color: 'white', '&:hover': { bgcolor: '#4f46e5' }, '&.Mui-disabled': { bgcolor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.3)' } }}
          >
            <Send size={18} />
          </IconButton>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

