import { createContext, useContext, useState, useEffect } from 'react';
import api from '../api/axios';

const AuthContext = createContext();

/**
 * Silently register the service worker and re-subscribe to push if permission
 * was previously granted. Called after every successful login/register flow.
 */
async function tryAutoSubscribePush() {
  try {
    if (
      !('Notification' in window) ||
      Notification.permission !== 'granted' ||
      !('serviceWorker' in navigator) ||
      !('PushManager' in window)
    ) return;

    const reg = await navigator.serviceWorker.register('/sw.js');
    await navigator.serviceWorker.ready;
    const existing = await reg.pushManager.getSubscription();
    const { data } = await api.get('/push/vapid-public-key');
    const rawKey = data.publicKey;
    const padding = '='.repeat((4 - (rawKey.length % 4)) % 4);
    const base64 = (rawKey + padding).replace(/-/g, '+').replace(/_/g, '/');
    const bytes = new Uint8Array(atob(base64).split('').map(c => c.charCodeAt(0)));

    const sub = existing || await reg.pushManager.subscribe({ userVisibleOnly: true, applicationServerKey: bytes });
    await api.post('/push/subscribe', { subscription: sub.toJSON() });
  } catch (e) {
    // Silent fail — user can enable manually from Navbar
  }
}

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      api.get('/auth/me')
        .then(res => { setUser(res.data); tryAutoSubscribePush(); })
        .catch(() => localStorage.removeItem('token'))
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = async (email, password) => {
    const { data } = await api.post('/auth/login', { email, password });
    localStorage.setItem('token', data.token);
    setUser(data.user);
    tryAutoSubscribePush();
    return data;
  };

  const register = async (payload) => {
    const { data } = await api.post('/auth/register', payload);
    localStorage.setItem('token', data.token);
    setUser(data.user);
    tryAutoSubscribePush();
    return data;
  };

  const googleLogin = async (payload) => {
    const { data } = await api.post('/auth/google', payload);
    localStorage.setItem('token', data.token);
    setUser(data.user);
    tryAutoSubscribePush();
    return data;
  };

  const logout = () => {
    localStorage.removeItem('token');
    setUser(null);
  };

  const updateUser = (updatedUser) => setUser(updatedUser);

  return (
    <AuthContext.Provider value={{ user, setUser, loading, login, register, googleLogin, logout, updateUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import React, { createContext, useContext, useEffect, useState } from 'react';
import { io } from 'socket.io-client';
import { useAuth } from './AuthContext';
import { toast } from 'react-hot-toast';

const SocketContext = createContext();

export const useSocket = () => {
    return useContext(SocketContext);
};

export const SocketProvider = ({ children }) => {
    const [socket, setSocket] = useState(null);
    const { user } = useAuth();

    useEffect(() => {
        if (!user) {
            if (socket) {
                socket.disconnect();
                setSocket(null);
            }
            return;
        }

        const newSocket = io(import.meta.env.VITE_API_URL?.replace('/api', '') || 'http://localhost:5001', {
            withCredentials: true
        });
        setSocket(newSocket);

        newSocket.emit('setup', user._id);

        newSocket.on('notification', (data) => {
            toast(data.message, {
                icon: '🔔',
                style: { borderRadius: '10px', background: '#333', color: '#fff' },
            });
        });

        newSocket.on('message_received', (message) => {
            if (!window.location.pathname.includes('/messages')) {
                const senderName = message.sender?.name || 'a connection';
                toast(`New message from ${senderName}`, {
                    icon: '💬',
                    style: { borderRadius: '10px', background: '#333', color: '#fff' },
                });
            }
        });

        newSocket.on('quest_completed', (data) => {
            toast.success(`🎉 Quest Completed: ${data.questName}\n+${data.xp} XP!`, {
                duration: 5000,
                style: { borderRadius: '16px', background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: '#fff', fontWeight: 'bold', padding: '16px' },
            });
        });

        return () => {
            newSocket.off('notification');
            newSocket.off('message_received');
            newSocket.off('quest_completed');
            newSocket.disconnect();
            setSocket(null);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [user]);

    return (
        <SocketContext.Provider value={{ socket }}>
            {children}
        </SocketContext.Provider>
    );
};

