            border: 1px solid ${isDark ? 'rgba(255, 255, 255, 0.05)' : 'rgba(0, 0, 0, 0.05)'};
            box-shadow: ${isDark ? '0 10px 40px rgba(0, 0, 0, 0.3)' : '0 10px 40px rgba(148, 163, 184, 0.15)'};
            border-radius: 24px;
            transition: all 0.3s ease-in-out;
