                    {rankBadge}
                  </Box>

                  <ListItemAvatar sx={{ mr: 2 }}>
                    <Avatar 
                      src={leader.avatar || undefined} 
                      sx={{ 
                        width: 56, 
                        height: 56, 
                        border: idx === 0 ? '3px solid #eab308' : 'none',
                        bgcolor: theme.palette.mode === 'dark' ? 'rgba(139, 92, 246, 0.2)' : 'rgba(139, 92, 246, 0.1)',
                        color: '#8b5cf6',
                        fontSize: '1.5rem',
                        fontWeight: 700
                      }}
                    >
                      {!leader.avatar && leader.name.charAt(0)}
                    </Avatar>
                  </ListItemAvatar>

                  <Box sx={{ flex: 1, minWidth: 0, display: 'flex', flexDirection: 'column', pr: 2 }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mb: 0.5 }}>
                      <Typography variant="h6" fontWeight={800} color="text.primary" noWrap>
                        {leader.name}
                      </Typography>
                      {isMe && (
                        <Chip label="You" size="small" sx={{ height: 20, fontSize: '0.65rem', fontWeight: 800, bgcolor: '#8b5cf6', color: 'white' }} />
                      )}
                    </Box>
                    <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap', mt: 0.5 }}>
                      <Chip 
                        size="small" 
                        label={`LVL ${leader.level || 1}`} 
                        sx={{ height: 20, fontSize: '0.7rem', fontWeight: 800, bgcolor: 'rgba(56, 189, 248, 0.1)', color: '#38bdf8' }} 
                      />
                      {leader.badges && leader.badges.slice(-2).map((b, i) => (
                         <Tooltip key={i} title={b}>
                           <Chip size="small" icon={<Star size={10} />} label={b.split(' ')[0]} sx={{ height: 20, fontSize: '0.65rem' }} />
                         </Tooltip>
                      ))}
                    </Box>
                  </Box>

                  <Box sx={{ display: 'flex', alignItems: 'center', gap: { xs: 2, sm: 4 }, ml: 'auto', flexShrink: 0 }}>
                    <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                      <Typography variant="subtitle1" fontWeight={800} sx={{ color: theme.palette.mode === 'dark' ? '#fb923c' : '#f97316', display: 'flex', alignItems: 'center', gap: 0.5 }}>
                        <Flame size={18} /> {leader.streak || 0}
                      </Typography>
                      <Typography variant="caption" color="text.secondary" sx={{ display: { xs: 'none', sm: 'block' }, fontWeight: 600 }}>
                        Day Streak
                      </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                      <Typography variant="subtitle1" fontWeight={900} color="#8b5cf6" sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                        <Target size={16} /> {(leader.xp || 0).toLocaleString()}
                      </Typography>
                      <Typography variant="caption" color="text.secondary" sx={{ display: { xs: 'none', sm: 'block' }, fontWeight: 600 }}>
                        Total XP
                      </Typography>
                    </Box>
                  </Box>
                </ListItem>
              </React.Fragment>
            );
          })}
          {leaders.length === 0 && (
            <ListItem sx={{ py: 8, justifyContent: 'center' }}>
              <Typography variant="body1" color="text.secondary" fontStyle="italic">
                No active players in the matrix yet.
              </Typography>
            </ListItem>
          )}
        </List>
      </Paper>
    </Container>
  );
}

import React, { useState } from 'react';
import { Link as RouterLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
// Removed Globe icon
import toast from 'react-hot-toast';
import { Box, Button, Container, TextField, Typography, Link, InputAdornment, IconButton } from '@mui/material';
import { Visibility, VisibilityOff, Email, Lock, Security } from '@mui/icons-material';
import { motion } from 'framer-motion';
import { GoogleLogin } from '@react-oauth/google';
import Logo from '../components/Logo';
import FloatingBackground from '../components/FloatingBackground';
import AuthCharacter from '../components/auth/AuthCharacter';
import MagneticButton from '../components/MagneticButton';

const staggerContainer = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.1, delayChildren: 0.1 } }
};

const popIn = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { type: "spring", stiffness: 100, damping: 15 } }
};

const inputStyles = {
  '& .MuiOutlinedInput-root': { 
    bgcolor: 'rgba(255,255,255,0.02)', color: 'white', borderRadius: 4, 
    '& fieldset': { borderColor: 'rgba(255,255,255,0.1)' },
    '&:hover fieldset': { borderColor: 'rgba(255,255,255,0.2)' },
    '&.Mui-focused fieldset': { borderColor: '#6366f1', borderWidth: 2 } 
  },
  '& .MuiInputLabel-root': { color: 'rgba(255,255,255,0.5)' },
  '& .MuiInputLabel-root.Mui-focused': { color: '#6366f1' }
};

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const { login, googleLogin } = useAuth();
  const navigate = useNavigate();

  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [charAction, setCharAction] = useState('lean');

  const trackMouse = (e) => {
    setMousePos({ 
      x: (e.clientX / window.innerWidth) * 2 - 1, 
      y: -(e.clientY / window.innerHeight) * 2 + 1 
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form.email, form.password);
      toast.success('Welcome back!');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSuccess = async (credentialResponse) => {
    setLoading(true);
    try {
      await googleLogin({ credential: credentialResponse.credential });
      toast.success('Welcome back!');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Google Auth failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box onMouseMove={trackMouse} sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: '#020617', p: 2, position: 'relative', overflow: 'hidden' }}>

      {/* Animated Abstract Background */}
      <FloatingBackground />

      {/* 3D Scrollytelling Character Overlay */}
      <Box sx={{ display: { xs: 'none', lg: 'block' } }}>
        <AuthCharacter action={charAction} mouse={mousePos} style={{ right: '10%', top: '50%', transform: 'translateY(-50%)', width: '400px', height: '60vh' }} />
      </Box>

      <Container maxWidth="xs" sx={{ position: 'relative', zIndex: 10 }}>
        <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ type: "spring", stiffness: 120, damping: 20 }}>
          <Box sx={{ 
            p: { xs: 4, sm: 5 }, borderRadius: '32px', backdropFilter: 'blur(24px)', 
            bgcolor: 'rgba(255, 255, 255, 0.02)', border: '1px solid rgba(255,255,255,0.05)',
            boxShadow: '0 20px 40px rgba(0,0,0,0.5)'
          }}>

            <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', mb: 5 }}>
              <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: "spring", delay: 0.2 }}>
                <Box sx={{ display: 'flex', justifyContent: 'center', mb: 3 }}>
                  <Logo size={64} showText={false} />
                </Box>
              </motion.div>
              <Typography component="h1" variant="h4" sx={{ fontWeight: 900, color: 'white', letterSpacing: '-1px', mb: 1 }}>
                Welcome back
              </Typography>
              <Typography variant="body1" color="rgba(255,255,255,0.5)">
                Enter your credentials to access your hubs.
              </Typography>
            </Box>

            <Box sx={{ mb: 3, display: 'flex', justifyContent: 'center' }}>
              <GoogleLogin
                onSuccess={handleGoogleSuccess}
                onError={() => toast.error('Google Sign In failed')}
                theme="filled_black"
                shape="pill"
                size="large"
                text="continue_with"
                width="310"
              />
            </Box>

            <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
              <Box sx={{ flex: 1, height: '1px', bgcolor: 'rgba(255,255,255,0.1)' }} />
              <Typography sx={{ mx: 2, color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem', fontWeight: 600 }}>OR</Typography>
              <Box sx={{ flex: 1, height: '1px', bgcolor: 'rgba(255,255,255,0.1)' }} />
            </Box>

            <motion.form variants={staggerContainer} initial="hidden" animate="visible" onSubmit={handleSubmit}>

              <motion.div variants={popIn}>
                <TextField
                  margin="normal" required fullWidth id="email" label="Email Address" name="email"
                  autoComplete="email" autoFocus value={form.email} onChange={e => setForm({ ...form, email: e.target.value })}
                  InputProps={{
                    startAdornment: <InputAdornment position="start"><Email sx={{ color: 'rgba(255,255,255,0.5)' }} /></InputAdornment>,
                  }}
                  sx={{ ...inputStyles, mb: 2.5 }}
                />
              </motion.div>

              <motion.div variants={popIn}>
                <TextField
                  margin="normal" required fullWidth name="password" label="Password"
                  type={showPassword ? 'text' : 'password'} id="password" autoComplete="current-password"
                  value={form.password} onChange={e => setForm({ ...form, password: e.target.value })}
                  InputProps={{
                    startAdornment: <InputAdornment position="start"><Lock sx={{ color: 'rgba(255,255,255,0.5)' }} /></InputAdornment>,
                    endAdornment: (
                      <InputAdornment position="end">
                        <IconButton aria-label="toggle password visibility" onClick={() => setShowPassword(!showPassword)} edge="end" sx={{ color: 'rgba(255,255,255,0.5)' }}>
