              <motion.div variants={popIn} onHoverStart={() => setCharAction('nod')} onHoverEnd={() => setCharAction('lean')}>
                <MagneticButton width="100%">
                  <Button
                    type="submit" fullWidth variant="contained" disabled={loading}
