import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  GoogleMap, useJsApiLoader, Marker, InfoWindow, Circle
} from '@react-google-maps/api';
import {
  Box, Typography, Avatar, Button, Chip, Slider, Paper,
  CircularProgress, useTheme, Tooltip, IconButton, Badge, TextField,
  InputAdornment
} from '@mui/material';
import {
  MapPin, Users, Navigation, RefreshCw, MessageCircle,
  UserPlus, Search, Layers, X
} from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import api from '../api/axios';
import toast from 'react-hot-toast';
import { useNavigate } from 'react-router-dom';

const LIBRARIES = ['places'];

const STUDY_STYLE_COLORS = {
  Visual: '#f59e0b',
  Auditory: '#10b981',
  'Reading/Writing': '#3b82f6',
  Kinesthetic: '#ef4444',
  Mixed: '#8b5cf6',
  Pomodoro: '#ec4899',
  default: '#8b5cf6',
};

const MAP_STYLES_DARK = [
  { elementType: 'geometry', stylers: [{ color: '#0f172a' }] },
  { elementType: 'labels.text.stroke', stylers: [{ color: '#0f172a' }] },
  { elementType: 'labels.text.fill', stylers: [{ color: '#94a3b8' }] },
  { featureType: 'road', elementType: 'geometry', stylers: [{ color: '#1e293b' }] },
  { featureType: 'road', elementType: 'geometry.stroke', stylers: [{ color: '#0f172a' }] },
  { featureType: 'road', elementType: 'labels.text.fill', stylers: [{ color: '#64748b' }] },
  { featureType: 'road.highway', elementType: 'geometry', stylers: [{ color: '#334155' }] },
  { featureType: 'water', elementType: 'geometry', stylers: [{ color: '#020617' }] },
  { featureType: 'water', elementType: 'labels.text.fill', stylers: [{ color: '#1e40af' }] },
  { featureType: 'poi', elementType: 'geometry', stylers: [{ color: '#0f172a' }] },
  { featureType: 'poi.park', elementType: 'geometry', stylers: [{ color: '#0f2c1a' }] },
  { featureType: 'transit', elementType: 'geometry', stylers: [{ color: '#1e293b' }] },
  { featureType: 'administrative', elementType: 'geometry.stroke', stylers: [{ color: '#334155' }] },
  { featureType: 'administrative.land_parcel', elementType: 'labels.text.fill', stylers: [{ color: '#475569' }] },
];

// Custom SVG pin factory for Google Maps — uses google.maps.Size/Point objects
function createGooglePin(color, isMe = false) {
  const w = isMe ? 48 : 38;
  const h = Math.round(w * 1.35);

  const pulseRing = isMe
    ? `<circle cx="${w / 2}" cy="${w / 2}" r="${w / 2 - 2}" fill="none" stroke="${color}" stroke-width="2" opacity="0.4"/>`
    : '';

  const cx = w / 2;
  const cy = w / 2;

  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">
    <defs>
      <filter id="s"><feDropShadow dx="0" dy="2" stdDeviation="2" flood-color="${color}" flood-opacity="0.35"/></filter>
      <radialGradient id="g" cx="35%" cy="30%" r="70%">
        <stop offset="0%" stop-color="#ffffff" stop-opacity="0.25"/>
        <stop offset="100%" stop-color="${color}" stop-opacity="0"/>
      </radialGradient>
    </defs>
    ${pulseRing}
    <path d="M${cx} 2 C${cx - 14} 2 ${cx - 20} ${cy - 4} ${cx - 20} ${cy}
             c0 ${cy + 4} ${20} ${h - cy - 2} ${20} ${h - cy - 2}
             s${20} ${-(h - cy - 2) + (cy + 4)} ${20} ${-(h - cy - 2) + (cy + 4)}
             C${cx + 20} ${cy - 4} ${cx + 14} 2 ${cx} 2z"
          fill="${color}" filter="url(#s)"/>
    <path d="M${cx} 2 C${cx - 14} 2 ${cx - 20} ${cy - 4} ${cx - 20} ${cy}
             c0 ${cy + 4} ${20} ${h - cy - 2} ${20} ${h - cy - 2}
             s${20} ${-(h - cy - 2) + (cy + 4)} ${20} ${-(h - cy - 2) + (cy + 4)}
             C${cx + 20} ${cy - 4} ${cx + 14} 2 ${cx} 2z"
          fill="url(#g)"/>
    <circle cx="${cx}" cy="${cy}" r="${isMe ? cx - 8 : cx - 10}" fill="white" opacity="0.9"/>
    ${isMe ? `<circle cx="${cx}" cy="${cy}" r="${cx - 16}" fill="${color}"/>` : ''}
  </svg>`;

  return {
    url: `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`,
    scaledSize: new window.google.maps.Size(w, h),
    anchor: new window.google.maps.Point(cx, h),
  };
}


export default function StudyMap() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const theme = useTheme();
  const isDark = theme.palette.mode === 'dark';

  const [myPos, setMyPos] = useState(null);
  const [nearbyUsers, setNearbyUsers] = useState([]);
  const [radius, setRadius] = useState(10); // km
  const [loading, setLoading] = useState(true);
  const [locationError, setLocationError] = useState(null);
  const [selectedUser, setSelectedUser] = useState(null);
  const [mapInstance, setMapInstance] = useState(null);
  const [filter, setFilter] = useState('');

  const apiKey = import.meta.env.VITE_GOOGLE_MAPS_API_KEY || '';

  const { isLoaded, loadError } = useJsApiLoader({
    googleMapsApiKey: apiKey,
    libraries: LIBRARIES,
  });

  const onMapLoad = useCallback((map) => {
    setMapInstance(map);
  }, []);

  const initLocation = useCallback(() => {
    setLoading(true);
    setLocationError(null);

    if (!navigator.geolocation) {
      setLocationError('Geolocation is not supported by your browser.');
      setLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async ({ coords: { latitude: lat, longitude: lng } }) => {
        setMyPos({ lat, lng });
        try {
          await api.put('/users/profile/location', { lat, lng });
        } catch {/*silent*/}
        await fetchNearby(lat, lng, radius);
        setLoading(false);
      },
      () => {
        setLocationError('Location access denied. Please allow location in your browser settings.');
        setLoading(false);
      },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  }, [radius]);

  const fetchNearby = async (lat, lng, km) => {
    try {
      const { data } = await api.get(`/users/nearby?lat=${lat}&lng=${lng}&radius=${km * 1000}`);
      setNearbyUsers(data);
    } catch {
      toast.error('Failed to fetch nearby users');
    }
  };

  useEffect(() => { initLocation(); }, []);

  const handleRadiusChange = async (_, val) => {
    setRadius(val);
    if (myPos) await fetchNearby(myPos.lat, myPos.lng, val);
  };

  const handleConnect = async (targetId) => {
    try {
      await api.post(`/users/connect/${targetId}`);
      toast.success('Connection request sent! 🎉');
    } catch (e) {
      toast.error(e?.response?.data?.message || 'Could not send request');
    }
  };

  const handleMessage = (targetId) => {
    navigate('/messages', { state: { openUserId: targetId } });
  };

  const handleCenterOnMe = () => {
    if (mapInstance && myPos) {
      mapInstance.panTo(myPos);
      mapInstance.setZoom(14);
    }
  };

  const filteredUsers = filter.trim()
    ? nearbyUsers.filter(u =>
        u.name?.toLowerCase().includes(filter.toLowerCase()) ||
        u.subjects?.some(s => s.toLowerCase().includes(filter.toLowerCase()))
      )
    : nearbyUsers;

  // ── Loading states ──────────────────────────────────────────────
  if (!isLoaded || loading) {
    return (
      <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '80vh', gap: 3 }}>
        <CircularProgress size={56} sx={{ color: '#6366f1' }} />
        <Typography variant="h6" fontWeight={700} color="text.secondary">
          {!isLoaded ? 'Loading Google Maps…' : 'Locating your study matrix…'}
        </Typography>
      </Box>
    );
  }

  if (loadError || !apiKey || apiKey === 'YOUR_GOOGLE_MAPS_API_KEY_HERE') {
    return (
      <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '80vh', gap: 3, p: 4, textAlign: 'center' }}>
        <MapPin size={64} color="#6366f1" />
        <Typography variant="h5" fontWeight={800}>Google Maps API Key Missing</Typography>
        <Typography color="text.secondary" maxWidth={500}>
          Add your key to <code>fe/.env</code>:<br/>
          <code style={{ background: 'rgba(99,102,241,0.1)', padding: '4px 8px', borderRadius: 6, fontFamily: 'monospace' }}>
            VITE_GOOGLE_MAPS_API_KEY=AIzaSy...
          </code>
          <br/><br/>Then restart the Vite dev server.
        </Typography>
        <Button variant="contained" href="https://console.cloud.google.com" target="_blank" sx={{ bgcolor: '#6366f1', borderRadius: 3, fontWeight: 700 }}>
          Get API Key (Free)
        </Button>
      </Box>
    );
  }

  if (locationError) {
    return (
      <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '80vh', gap: 3, p: 4, textAlign: 'center' }}>
        <Navigation size={64} color="#ef4444" />
        <Typography variant="h5" fontWeight={800}>{locationError}</Typography>
        <Button variant="contained" onClick={initLocation} sx={{ bgcolor: '#6366f1', borderRadius: 3, fontWeight: 700 }}>
          Try Again
        </Button>
      </Box>
    );
  }

  return (
    <Box sx={{ position: 'relative', height: 'calc(100vh - 72px)', overflow: 'hidden' }}>

      {/* ── Top Control Panel ── */}
      <Paper elevation={8} sx={{
        position: 'absolute', top: 16, left: '50%', transform: 'translateX(-50%)',
        zIndex: 10, borderRadius: '20px', p: 2, minWidth: 340, maxWidth: '92vw',
        bgcolor: isDark ? 'rgba(2,6,23,0.92)' : 'rgba(255,255,255,0.96)',
        backdropFilter: 'blur(24px)',
        border: `1px solid ${isDark ? 'rgba(99,102,241,0.2)' : 'rgba(99,102,241,0.12)'}`,
        boxShadow: '0 8px 32px rgba(0,0,0,0.2)',
        display: 'flex', flexDirection: 'column', gap: 1.5
      }}>

        {/* Header */}
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <Typography variant="h6" fontWeight={900} display="flex" alignItems="center" gap={1}>
            <MapPin size={22} color="#6366f1" /> Nearby Scholars
          </Typography>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <Chip
              icon={<Users size={14} />}
              label={`${filteredUsers.length} found`}
              size="small"
              sx={{ bgcolor: 'rgba(99,102,241,0.12)', color: '#6366f1', fontWeight: 700 }}
            />
            <Tooltip title="Refresh">
              <IconButton size="small" onClick={() => myPos && fetchNearby(myPos.lat, myPos.lng, radius)}>
                <RefreshCw size={16} />
              </IconButton>
            </Tooltip>
            <Tooltip title="Centre on me">
              <IconButton size="small" onClick={handleCenterOnMe} sx={{ color: '#6366f1' }}>
                <Navigation size={16} />
              </IconButton>
            </Tooltip>
          </Box>
        </Box>

        {/* Search filter */}
        <TextField
          size="small"
          placeholder="Filter by name or subject…"
          value={filter}
          onChange={e => setFilter(e.target.value)}
          InputProps={{
            startAdornment: <InputAdornment position="start"><Search size={16} /></InputAdornment>,
            endAdornment: filter ? (
              <InputAdornment position="end">
                <IconButton size="small" onClick={() => setFilter('')}><X size={14} /></IconButton>
              </InputAdornment>
            ) : null,
          }}
          sx={{ '& .MuiOutlinedInput-root': { borderRadius: '12px' } }}
        />

        {/* Radius slider */}
        <Box sx={{ px: 1 }}>
          <Typography variant="caption" fontWeight={700} color="text.secondary">
            Radius: <strong>{radius} km</strong>
          </Typography>
          <Slider
            value={radius} min={1} max={50} step={1}
            onChange={handleRadiusChange}
            valueLabelDisplay="auto"
            valueLabelFormat={v => `${v} km`}
            sx={{ color: '#6366f1', '& .MuiSlider-thumb': { width: 16, height: 16 }, mt: 0.5 }}
          />
        </Box>
      </Paper>

      {/* ── Legend (bottom-right) ── */}
      <Paper elevation={4} sx={{
        position: 'absolute', bottom: 24, right: 16, zIndex: 10,
        borderRadius: '16px', p: 2,
        bgcolor: isDark ? 'rgba(2,6,23,0.92)' : 'rgba(255,255,255,0.95)',
        backdropFilter: 'blur(12px)',
        border: `1px solid ${isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)'}`,
        minWidth: 150
      }}>
        <Typography variant="caption" fontWeight={800} color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: 1, display: 'block', mb: 1 }}>
          Study Style
        </Typography>
        {Object.entries(STUDY_STYLE_COLORS).filter(([k]) => k !== 'default').map(([style, color]) => (
          <Box key={style} sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.4 }}>
            <Box sx={{ width: 10, height: 10, borderRadius: '50%', bgcolor: color, flexShrink: 0 }} />
            <Typography variant="caption" fontWeight={600}>{style}</Typography>
          </Box>
        ))}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 1, pt: 1, borderTop: '1px solid', borderColor: 'divider' }}>
          <Box sx={{ width: 10, height: 10, borderRadius: '50%', bgcolor: '#6366f1', flexShrink: 0 }} />
          <Typography variant="caption" fontWeight={700} color="#6366f1">You</Typography>
        </Box>
      </Paper>

      {/* ── Google Map ── */}
      {myPos && (
        <GoogleMap
          mapContainerStyle={{ width: '100%', height: '100%' }}
          center={myPos}
          zoom={13}
          onLoad={onMapLoad}
          options={{
            styles: isDark ? MAP_STYLES_DARK : [],
            disableDefaultUI: false,
            zoomControl: true,
            streetViewControl: false,
            mapTypeControl: false,
            fullscreenControl: true,
            clickableIcons: false,
          }}
        >
          {/* My position marker */}
          <Marker
            position={myPos}
            icon={createGooglePin('#6366f1', true)}
            title={`${user?.name} (You)`}
            onClick={() => setSelectedUser('me')}
            zIndex={1000}
          />

          {/* Radius circle */}
          <Circle
            center={myPos}
            radius={radius * 1000}
            options={{
              fillColor: '#6366f1',
              fillOpacity: 0.05,
              strokeColor: '#6366f1',
              strokeOpacity: 0.4,
              strokeWeight: 1.5,
            }}
          />

          {/* "Me" InfoWindow */}
          {selectedUser === 'me' && (
            <InfoWindow position={myPos} onCloseClick={() => setSelectedUser(null)}>
              <Box sx={{ textAlign: 'center', p: 0.5, minWidth: 140 }}>
                <Avatar src={user?.avatar} sx={{ width: 44, height: 44, mx: 'auto', mb: 1, bgcolor: '#6366f1', fontWeight: 700 }}>
                  {user?.name?.[0]}
                </Avatar>
                <Typography fontWeight={800} fontSize={14}>{user?.name}</Typography>
                <Chip label="You" size="small" sx={{ bgcolor: '#6366f1', color: 'white', fontWeight: 700, mt: 0.5 }} />
              </Box>
            </InfoWindow>
          )}

          {/* Nearby user markers */}
          {filteredUsers.map(u => {
            const coords = u.geoLocation?.coordinates;
            if (!coords || coords.length < 2) return null;
            const pos = { lat: coords[1], lng: coords[0] };
            const pinColor = STUDY_STYLE_COLORS[u.studyStyle] || STUDY_STYLE_COLORS.default;

            return (
              <React.Fragment key={u._id}>
                <Marker
                  position={pos}
                  icon={createGooglePin(pinColor)}
                  title={u.name}
                  onClick={() => setSelectedUser(selectedUser?._id === u._id ? null : u)}
                />

                {selectedUser?._id === u._id && (
                  <InfoWindow position={pos} onCloseClick={() => setSelectedUser(null)}>
                    <Box sx={{ minWidth: 220, maxWidth: 260, p: 0.5 }}>
                      {/* Header */}
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mb: 1.5 }}>
                        <Avatar src={u.avatar} sx={{ width: 50, height: 50, bgcolor: pinColor, fontWeight: 800, fontSize: 22, flexShrink: 0 }}>
                          {u.name?.[0]}
                        </Avatar>
                        <Box>
                          <Typography fontWeight={900} fontSize={15} lineHeight={1.2}>{u.name}</Typography>
                          <Typography variant="caption" color="text.secondary" fontWeight={600}>
                            {u.university || 'Independent Scholar'}
                          </Typography>
                        </Box>
                      </Box>

                      {/* Stats row */}
                      <Box sx={{ display: 'flex', gap: 0.75, mb: 1.5, flexWrap: 'wrap' }}>
                        <Chip label={`⚡ Lvl ${u.level || 1}`} size="small" sx={{ bgcolor: 'rgba(99,102,241,0.1)', color: '#6366f1', fontWeight: 700, fontSize: 11 }} />
                        <Chip label={u.studyStyle || 'Mixed'} size="small" sx={{ bgcolor: `${pinColor}20`, color: pinColor, fontWeight: 700, fontSize: 11 }} />
                      </Box>

                      {/* Subjects */}
                      {u.subjects?.length > 0 && (
                        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5, mb: 1.5 }}>
                          {u.subjects.slice(0, 4).map(s => (
                            <Chip key={s} label={s} size="small" sx={{ fontSize: 10, fontWeight: 600 }} />
                          ))}
                        </Box>
                      )}

                      {/* CTAs */}
                      <Box sx={{ display: 'flex', gap: 1 }}>
                        <Button
                          fullWidth size="small" variant="contained"
                          startIcon={<UserPlus size={13} />}
                          onClick={() => handleConnect(u._id)}
                          sx={{ bgcolor: '#6366f1', borderRadius: '10px', fontWeight: 700, fontSize: 12, py: 0.8, '&:hover': { bgcolor: '#4f46e5' } }}
                        >
                          Connect
                        </Button>
                        <Button
                          fullWidth size="small" variant="outlined"
                          startIcon={<MessageCircle size={13} />}
                          onClick={() => handleMessage(u._id)}
                          sx={{ borderColor: '#6366f1', color: '#6366f1', borderRadius: '10px', fontWeight: 700, fontSize: 12, py: 0.8 }}
                        >
                          Message
                        </Button>
                      </Box>
                    </Box>
                  </InfoWindow>
                )}
              </React.Fragment>
            );
          })}
        </GoogleMap>
      )}
    </Box>
  );
}

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api/axios';
import NotesUploader from '../components/NotesUploader';
import VideoRoom from '../components/VideoRoom';
import SharedWhiteboard from '../components/SharedWhiteboard';
import StudyRoomChat from '../components/StudyRoomChat';
import { ArrowLeft, Users, Loader2, Maximize, MessageSquare, FileText } from 'lucide-react';
import { toast } from 'react-hot-toast';
import { Box, Typography, IconButton, Button } from '@mui/material';
import { motion, AnimatePresence } from 'framer-motion';
import { io } from 'socket.io-client';

export default function StudyRoom() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [session, setSession] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showPanel, setShowPanel] = useState(true);
  const [activeTab, setActiveTab] = useState('chat');
  const [socket, setSocket] = useState(null);
  const whiteboardRef = useRef(null);

  useEffect(() => {
    const fetchSessionAndJoin = async () => {
      try {
        // Fetch the global session via the new dedicated endpoint
        const res = await api.get(`/sessions/${id}`);
        const found = res.data;

        if (!found) {
          toast.error("Session not found");
          return navigate('/sessions');
        }

        // Check if user is already a participant
        const isParticipant = found.participants?.some(p => p._id === user?._id || p === user?._id);
        const isHost = found.host?._id === user?._id || found.host === user?._id;

        if (!isParticipant && !isHost) {
          // Attempt Auto-Join sequence for direct link sharers
          try {
            await api.post(`/sessions/${id}/join`);
            toast.success("Automatically joined the session via direct link!");
            // Re-fetch populated session
            const joinedRes = await api.get(`/sessions/${id}`);
            setSession(joinedRes.data);
          } catch (joinErr) {
            toast.error(joinErr.response?.data?.message || "Session is full or unavailable.");
            return navigate('/sessions');
          }
        } else {
          // Already a participant
          setSession(found);
        }

      } catch (err) {
        console.error("StudyRoom Load Error:", err);
        toast.error(err.response?.data?.message || err.message || 'Failed to load study room or verify permissions');
        navigate('/sessions');
      } finally {
        setLoading(false);
      }
    };

    if (user) {
      fetchSessionAndJoin();
    }
  }, [id, navigate, user]);

  useEffect(() => {
    if (!session) return;
    const wsUrl = import.meta.env.VITE_API_URL?.replace('/api', '') || 'http://localhost:5001';
    const newSocket = io(wsUrl, { withCredentials: true });
    newSocket.emit('join_study_room', id);
    setSocket(newSocket);
    return () => newSocket.disconnect();
  }, [id, session]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement && whiteboardRef.current) {
      whiteboardRef.current.requestFullscreen().catch(err => {
        toast.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else if (document.fullscreenElement) {
      document.exitFullscreen();
    }
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', bgcolor: '#0f1115' }}>
        <Loader2 className="animate-spin text-blue-500" size={40} />
      </Box>
    );
  }
  if (!session) return null;

  return (
    <Box sx={{ display: 'flex', height: '100vh', bgcolor: '#0f111a', color: 'white', overflow: 'hidden', fontFamily: 'Inter, sans-serif' }}>
       {/* Main Canvas Area */}
       <Box sx={{ flex: 1, position: 'relative', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
           {/* Top Nav Overlay */}
           <Box sx={{ position: 'absolute', top: 0, left: 0, right: 0, zIndex: 50, p: 3, display: 'flex', justifyContent: 'space-between', alignItems: 'center', pointerEvents: 'none' }}>
               <Box sx={{ pointerEvents: 'auto', display: 'flex', alignItems: 'center', gap: 2, background: 'rgba(20,20,30,0.6)', backdropFilter: 'blur(16px)', px: 3, py: 1.5, borderRadius: '100px', border: '1px solid rgba(255,255,255,0.08)', boxShadow: '0 8px 32px rgba(0,0,0,0.2)' }}>
                   <IconButton onClick={() => navigate('/sessions')} sx={{ color: 'white', bgcolor: 'rgba(255,255,255,0.1)', '&:hover': { bgcolor: 'rgba(255,255,255,0.2)' } }}><ArrowLeft size={18} /></IconButton>
                   <Typography variant="subtitle1" fontWeight={700} sx={{ letterSpacing: 0.5 }}>{session.title}</Typography>
                   <Box sx={{ width: 4, height: 4, borderRadius: '50%', bgcolor: 'rgba(255,255,255,0.3)' }} />
                   <Typography variant="body2" color="rgba(255,255,255,0.7)" fontWeight={500}>{session.subject}</Typography>
               </Box>

               <Box sx={{ pointerEvents: 'auto', background: 'rgba(20,20,30,0.6)', backdropFilter: 'blur(16px)', px: 2.5, py: 1.5, borderRadius: '100px', border: '1px solid rgba(255,255,255,0.08)', boxShadow: '0 8px 32px rgba(0,0,0,0.2)', display: 'flex', alignItems: 'center', gap: 2 }}>
                   <Typography variant="body2" fontWeight={600} display="flex" alignItems="center" gap={1}>
                      <Users size={16} color="#60a5fa" /> 
                      {session.participants?.length || 1} / {session.maxParticipants || '∞'}
                   </Typography>
                   <Box sx={{ width: '1px', height: 16, bgcolor: 'rgba(255,255,255,0.2)' }} />
                   <IconButton size="small" onClick={toggleFullscreen} sx={{ color: 'white', '&:hover': { color: '#60a5fa' } }} title="Fullscreen Whiteboard">
                     <Maximize size={16} />
                   </IconButton>
               </Box>
           </Box>

           {/* Whiteboard occupying the entire background */}
           <Box ref={whiteboardRef} sx={{ position: 'absolute', inset: 0, zIndex: 10, bgcolor: '#0f111a' }}>
             {socket && <SharedWhiteboard roomId={id} socket={socket} />}
           </Box>

           {/* Floating Video Dock on the left bottom */}
           <Box sx={{ position: 'absolute', bottom: 32, left: 32, zIndex: 50, pointerEvents: 'none', width: 'auto', maxWidth: 1200 }}>
              {socket && <VideoRoom roomId={id} socket={socket} onTogglePanel={() => setShowPanel(!showPanel)} showPanel={showPanel} />}
           </Box>
       </Box>

       {/* Collapsible Side Panel */}
       <AnimatePresence>
         {showPanel && (
            <motion.div
               initial={{ width: 0, opacity: 0 }}
               animate={{ width: 400, opacity: 1 }}
               exit={{ width: 0, opacity: 0 }}
               transition={{ type: 'spring', damping: 25, stiffness: 200 }}
               style={{ borderLeft: '1px solid rgba(255,255,255,0.05)', background: '#13151a', display: 'flex', flexDirection: 'column', zIndex: 60 }}
            >
               <Box sx={{ p: 3, flex: 1, display: 'flex', flexDirection: 'column', gap: 2, overflowY: 'hidden' }}>
                   {/* Tabs Nav */}
                   <Box sx={{ display: 'flex', bgcolor: 'rgba(0,0,0,0.3)', borderRadius: 3, p: 0.5 }}>
                     <Button 
                       fullWidth 
                       onClick={() => setActiveTab('chat')} 
                       sx={{ borderRadius: 2.5, bgcolor: activeTab === 'chat' ? 'rgba(59,130,246,0.2)' : 'transparent', color: activeTab === 'chat' ? '#60a5fa' : 'rgba(255,255,255,0.5)', py: 1, fontWeight: 700, textTransform: 'none', transition: 'all 0.2s', '&:hover': { bgcolor: activeTab === 'chat' ? 'rgba(59,130,246,0.25)' : 'rgba(255,255,255,0.05)' } }}
                     >
                       <MessageSquare size={16} style={{ marginRight: 8 }} /> Chat
                     </Button>
                     <Button 
                       fullWidth 
                       onClick={() => setActiveTab('notes')} 
                       sx={{ borderRadius: 2.5, bgcolor: activeTab === 'notes' ? 'rgba(59,130,246,0.2)' : 'transparent', color: activeTab === 'notes' ? '#60a5fa' : 'rgba(255,255,255,0.5)', py: 1, fontWeight: 700, textTransform: 'none', transition: 'all 0.2s', '&:hover': { bgcolor: activeTab === 'notes' ? 'rgba(59,130,246,0.25)' : 'rgba(255,255,255,0.05)' } }}
                     >
                       <FileText size={16} style={{ marginRight: 8 }} /> Notes
                     </Button>
                  </Box>

                  {/* Tab Content Area */}
                  <Box sx={{ flex: 1, pt: 1, overflowY: 'auto', '&::-webkit-scrollbar': { width: 6 }, '&::-webkit-scrollbar-thumb': { bgcolor: 'rgba(255,255,255,0.1)', borderRadius: 10 }, display: 'flex', flexDirection: 'column' }}>
                       {activeTab === 'chat' ? (
                         <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column', animation: 'fadeIn 0.2s ease-in-out' }}>
                           {socket && <StudyRoomChat socket={socket} roomId={id} />}
                         </Box>
                       ) : (
                         <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column', animation: 'fadeIn 0.2s ease-in-out' }}>
                           <NotesUploader session={session} setSession={setSession} />
                         </Box>
                       )}
                  </Box>
               </Box>
            </motion.div>
         )}
       </AnimatePresence>
    </Box>
  );
}

import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';
import { User, MapPin, GraduationCap, BookOpen, MessageCircle, UserPlus, Pencil, UserMinus, Trophy, Flame, Clock, Star, Github, Linkedin, Instagram, BadgeCheck, Globe, Target } from 'lucide-react';
import toast from 'react-hot-toast';
import ActivityHeatmap from '../components/profile/ActivityHeatmap';
import MindMapModal from '../components/profile/MindMapModal';
import { Container, Card, Box, Avatar, Typography, Button, IconButton, Chip, Grid, LinearProgress, useTheme, CardContent, CircularProgress } from '@mui/material';

export default function UserProfile() {
  const { id } = useParams();
  const { user: me } = useAuth();
  const navigate = useNavigate();
  const targetId = id || me?._id;
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [connecting, setConnecting] = useState(false);
  const [ratings, setRatings] = useState({ average: 0, count: 0, reviews: [] });
  const [endorsements, setEndorsements] = useState([]);
  const [mapOpen, setMapOpen] = useState(false);
  const theme = useTheme();

  useEffect(() => {
    if (!targetId) return;
    Promise.all([
      api.get(`/users/${targetId}`),
      api.get(`/ratings/${targetId}`),
      api.get(`/gamification/endorsements/${targetId}`)
    ])
      .then(([profileRes, ratingsRes, endoRes]) => {
        setProfile(profileRes.data);
        setRatings(ratingsRes.data);
        setEndorsements(endoRes.data);
      })
      .catch((err) => {
         console.error(err);
         toast.error('User not found');
      })
      .finally(() => setLoading(false));
  }, [targetId]);

  const handleConnect = async () => {
    setConnecting(true);
    try {
      await api.post(`/users/connect/${id}`);
      toast.success('Connection request sent!');
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
    finally { setConnecting(false); }
  };

  const handleDisconnect = async () => {
    if (!window.confirm('Are you sure you want to disconnect?')) return;
    try {
      await api.post(`/users/disconnect/${id}`);
      toast.success('Disconnected successfully');
      window.location.reload();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to disconnect'); }
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 10 }}>
        <CircularProgress />
      </Box>
    );
  }
  if (!profile) return <Box textAlign="center" py={10} color="text.secondary">User not found</Box>;

  const isConnected = me?.connections?.includes(id);
  const hasSentRequest = me?.sentRequests?.includes(id);

  const calculateCompleteness = (p) => {
    if (!p) return 0;
    const fields = [p.avatar, p.bio, p.subjects?.length > 0, p.university, p.location, p.studyStyle];
    const filled = fields.filter(Boolean).length;
    return Math.round((filled / fields.length) * 100);
  };
  const completeness = calculateCompleteness(profile);

  return (
    <Container maxWidth="md" sx={{ py: 4, mb: 10 }}>
      <Card elevation={theme.palette.mode === 'dark' ? 8 : 4} sx={{ borderRadius: 6, overflow: 'visible', position: 'relative' }}>
        {/* Cover Gradient Layer */}
        <Box sx={{ 
          height: { xs: 160, sm: 224 }, 
          background: 'linear-gradient(to right, #2563eb, #4f46e5, #9333ea)', 
          position: 'relative', 
          overflow: 'hidden',
          borderTopLeftRadius: 24,
          borderTopRightRadius: 24
        }}>
          <Box sx={{ position: 'absolute', inset: 0, opacity: 0.3, backgroundImage: 'url("https://www.transparenttextures.com/patterns/cubes.png")', mixBlendMode: 'overlay' }} />
          <Box sx={{ position: 'absolute', bottom: 0, width: '100%', height: '50%', background: 'linear-gradient(to top, rgba(0,0,0,0.2), transparent)' }} />
        </Box>

        {/* Floating Avatar Core */}
        <Avatar 
          src={profile.avatar || undefined} 
          sx={{ 
            width: { xs: 112, sm: 128 }, 
            height: { xs: 112, sm: 128 }, 
            position: 'absolute', 
            top: { xs: 112, sm: 160 }, 
            left: { xs: 24, sm: 40 }, 
            border: `4px solid ${theme.palette.background.paper}`, 
            boxShadow: theme.shadows[10], 
            bgcolor: 'background.paper', 
            color: 'text.disabled',
            zIndex: 10,
            transition: 'transform 0.2s',
            '&:hover': { transform: 'scale(1.05)' }
          }}
        >
          {!profile.avatar && <User size={48} />}
        </Avatar>

        {/* Informational Matrix */}
        <Box sx={{ px: { xs: 3, sm: 5 }, pt: { xs: 8, sm: 10 }, pb: 5 }}>
          <Box sx={{ display: 'flex', flexDirection: { xs: 'column', sm: 'row' }, justifyContent: 'space-between', alignItems: { xs: 'flex-start', sm: 'flex-end' }, gap: 3, mb: 4 }}>
            <Box>
              <Typography variant="h3" fontWeight={900} color="text.primary" sx={{ letterSpacing: -0.5 }}>
                {profile.name}
              </Typography>
              <Box sx={{ display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 2, mt: 1, color: 'text.secondary', fontWeight: 500 }}>
                {profile.university && (
                  <Typography variant="body2" sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <GraduationCap size={16} color={theme.palette.primary.main} /> {profile.university}
                  </Typography>
                )}
                {profile.location && (
                  <Typography variant="body2" sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <MapPin size={16} color={theme.palette.secondary.main} /> {profile.location}
                  </Typography>
                )}
                {profile.timezone && (
                  <Typography variant="body2" sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <Globe size={16} color="#06b6d4" /> {profile.timezone}
                  </Typography>
                )}
                {ratings.count > 0 && (
                  <Typography variant="body2" sx={{ display: 'flex', alignItems: 'center', gap: 0.5, color: '#ca8a04' }}>
                    <Star size={16} fill="currentColor" /> {ratings.average} ({ratings.count})
                  </Typography>
                )}
              </Box>

              {/* Trust Badges */}
              {profile.socialLinks && (profile.socialLinks.github || profile.socialLinks.linkedin || profile.socialLinks.instagram || profile.isVerified) && (
                <Box sx={{ display: 'flex', gap: 1.5, mt: 2, alignItems: 'center' }}>
                  {profile.isVerified && (
                    <Chip size="small" icon={<BadgeCheck size={14} color="#3b82f6" />} label="Verified Scholar" sx={{ bgcolor: 'rgba(59,130,246,0.1)', color: '#3b82f6', fontWeight: 800, borderRadius: 1.5, '& .MuiChip-icon': { color: '#3b82f6' } }} />
                  )}
                  {profile.socialLinks.github && (
                    <IconButton size="small" component="a" href={`https://github/${profile.socialLinks.github}`} target="_blank" sx={{ bgcolor: 'rgba(255,255,255,0.05)' }}>
                      <Github size={18} />
                    </IconButton>
                  )}
                  {profile.socialLinks.linkedin && (
                    <IconButton size="small" component="a" href={`https://linkedin.com/in/${profile.socialLinks.linkedin}`} target="_blank" sx={{ bgcolor: 'rgba(255,255,255,0.05)' }}>
                      <Linkedin size={18} color="#0a66c2" />
                    </IconButton>
                  )}
                  {profile.socialLinks.instagram && (
                    <IconButton size="small" component="a" href={`https://instagram.com/${profile.socialLinks.instagram}`} target="_blank" sx={{ bgcolor: 'rgba(255,255,255,0.05)' }}>
                      <Instagram size={18} color="#e1306c" />
                    </IconButton>
                  )}
                </Box>
              )}
            </Box>

            {/* Tactical Engagements */}
            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1.5, width: { xs: '100%', sm: 'auto' } }}>
              <Button 
                variant="outlined" 
                onClick={async () => {
                   const toastId = toast.loading('Generating Secure Academic Resume...');
                   try {
                     const { jsPDF } = await import('jspdf');
                     const doc = new jsPDF();
                     doc.setFont('helvetica', 'bold');
                     doc.setFontSize(22);
                     doc.text(`${profile.name} - Academic Portfolio`, 20, 20);
                     doc.setFontSize(12);
                     doc.setFont('helvetica', 'normal');
                     doc.text(`University: ${profile.university || 'N/A'}`, 20, 35);
                     doc.text(`Location: ${profile.location || 'N/A'}`, 20, 45);
                     doc.text(`Total Study Hours: ${profile.studyHours || 0} hrs`, 20, 55);
                     doc.text(`Current Streak: ${profile.streak || 0} days`, 20, 65);
                     doc.text(`League: ${profile.league || 'BRONZE'}`, 20, 75);
                     doc.text(`Subjects Mastered: ${profile.subjects?.join(', ') || 'None'}`, 20, 85);
                     doc.text(`Cognitive Style: ${profile.studyStyle}`, 20, 95);
                     doc.text(`Badges: ${profile.badges?.join(', ') || 'None'}`, 20, 105);

                     doc.setFont('helvetica', 'italic');
                     doc.text(`"Verified on StudyFriend Framework"`, 20, 280);

                     doc.save(`${profile.name.replace(/\s+/g, '_')}_Academic_Resume.pdf`);
                     toast.success('Resume Decrypted & Exported successfully!', { id: toastId });
                   } catch (err) {
                     toast.error('Failed to generate PDF matrix.', { id: toastId });
                   }
                }}
                sx={{ flex: { xs: 1, sm: 'none' }, borderRadius: 2, fontWeight: 700, borderColor: 'primary.main', color: 'primary.main' }}
              >
                📥 Export Resume 
              </Button>

              {(targetId === me?._id || me?.isAdmin) && (
                <Button 
                  variant="outlined" 
                  onClick={() => navigate(targetId === me?._id ? '/profile/edit' : `/admin/user/${targetId}/edit`)} 
                  startIcon={<Pencil size={16} />}
                  sx={{ flex: { xs: 1, sm: 'none' }, borderRadius: 2, fontWeight: 700 }}
                >
                  Edit Profile
                </Button>
              )}
              {targetId !== me?._id && (
                <>
                  {isConnected ? (
                    <>
                      <Button 
                        variant="contained" 
                        onClick={() => navigate(`/messages?with=${id}`)}
                        startIcon={<MessageCircle size={18} />}
                        sx={{ flex: { xs: 1, sm: 'none' }, borderRadius: 2, fontWeight: 700, background: 'linear-gradient(to right, #2563eb, #4f46e5)' }}
                      >
                        Message
                      </Button>
                      <Button 
                        variant="outlined" 
                        color="error" 
                        onClick={handleDisconnect} 
                        startIcon={<UserMinus size={18} />}
                        sx={{ flex: { xs: 1, sm: 'none' }, borderRadius: 2, fontWeight: 700 }}
                      >
                        Disconnect
                      </Button>
                    </>
                  ) : hasSentRequest ? (
                    <Button variant="outlined" disabled sx={{ flex: { xs: 1, sm: 'none' }, borderRadius: 2, fontWeight: 700 }}>
                      Request Pending
                    </Button>
                  ) : (
                    <Button 
                      variant="contained" 
                      onClick={handleConnect} 
                      disabled={connecting} 
                      startIcon={<UserPlus size={18} />}
                      sx={{ flex: { xs: 1, sm: 'none' }, borderRadius: 2, fontWeight: 700, background: 'linear-gradient(to right, #2563eb, #4f46e5)' }}
                    >
                      {connecting ? 'Sending...' : 'Connect'}
                    </Button>
                  )}
                </>
              )}
            </Box>
          </Box>

          {/* Gamification Stats */}
          <Grid container spacing={2} sx={{ mt: 2 }}>
            <Grid item xs={6} sm={3}>
              <Card variant="outlined" sx={{ borderRadius: 4, height: '100%', p: 2, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center', bgcolor: 'background.default' }}>
                <Clock size={24} color={theme.palette.primary.main} style={{ marginBottom: 8 }} />
                <Typography variant="h5" fontWeight={800} color="text.primary">{profile.studyHours || 0}</Typography>
                <Typography variant="caption" fontWeight={600} color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: 1 }}>Study Hours</Typography>
              </Card>
            </Grid>
            <Grid item xs={6} sm={3}>
              <Card variant="outlined" sx={{ borderRadius: 4, height: '100%', p: 2, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center', bgcolor: 'background.default' }}>
                <Flame size={24} color={theme.palette.warning.main} style={{ marginBottom: 8 }} />
                <Typography variant="h5" fontWeight={800} color="text.primary">{profile.streak || 0}</Typography>
                <Typography variant="caption" fontWeight={600} color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: 1 }}>Day Streak</Typography>
              </Card>
            </Grid>
            <Grid item xs={12} sm={6}>
              <Card variant="outlined" sx={{ borderRadius: 4, height: '100%', p: 2, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center', bgcolor: 'background.default' }}>
                <Trophy size={24} color="#eab308" style={{ marginBottom: 8 }} />
                <Typography variant="h6" fontWeight={800} color="text.primary" noWrap sx={{ width: '100%' }}>{profile.badges?.length > 0 ? profile.badges.join(', ') : 'Novice Scholar'}</Typography>
                <Typography variant="caption" fontWeight={600} color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: 1 }}>Current Rank / Badges</Typography>
              </Card>
            </Grid>
          </Grid>

          {/* Weekly Master Goals */}
          {profile.weeklyGoals?.length > 0 && (
            <Card variant="outlined" sx={{ mt: 3, p: 3, borderRadius: 4, bgcolor: 'background.paper', borderColor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)' }}>
              <Typography variant="h6" fontWeight={800} color="text.primary" display="flex" alignItems="center" gap={1} mb={3}>
                <Target size={20} color="#ec4899" /> Weekly Master Goals
              </Typography>
              <Grid container spacing={3}>
                {profile.weeklyGoals.map((goal, idx) => {
                  const progressPct = Math.min(((goal.currentHours || 0) / goal.targetHours) * 100, 100) || 0;
                  return (
                    <Grid item xs={12} sm={6} key={idx}>
                      <Box sx={{ p: 2, borderRadius: 3, bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.02)' }}>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                          <Typography variant="subtitle2" fontWeight={700} noWrap sx={{ maxWidth: '70%' }}>{goal.title}</Typography>
                          <Typography variant="caption" fontWeight={800} color="text.secondary">{goal.currentHours || 0} / {goal.targetHours}h</Typography>
                        </Box>
                        <LinearProgress 
                          variant="determinate" 
                          value={progressPct} 
                          sx={{ 
                            height: 8, borderRadius: 4, 
                            bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)',
                            '& .MuiLinearProgress-bar': {
                              background: progressPct >= 100 ? '#10b981' : 'linear-gradient(90deg, #ec4899, #8b5cf6)'
                            }
                          }} 
                        />
                      </Box>
                    </Grid>
                  );
                })}
              </Grid>
            </Card>
          )}

          {/* Activity Heatmap Widget */}
          <ActivityHeatmap userId={targetId} />

          {/* Profile Completeness for Me */}
          {targetId === me?._id && completeness < 100 && (
            <Card variant="outlined" sx={{ mt: 3, p: 2.5, borderRadius: 4, bgcolor: theme.palette.mode === 'dark' ? 'rgba(67, 56, 202, 0.1)' : 'rgba(224, 231, 255, 0.5)', borderColor: 'rgba(99, 102, 241, 0.2)' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                <Typography variant="body2" fontWeight={800} color="primary.main">Profile Completeness</Typography>
                <Typography variant="body2" fontWeight={800} color="primary.main">{completeness}%</Typography>
              </Box>
              <LinearProgress variant="determinate" value={completeness} sx={{ height: 10, borderRadius: 5, bgcolor: theme.palette.mode === 'dark' ? 'rgba(79, 70, 229, 0.2)' : 'rgba(99, 102, 241, 0.1)' }} />
              <Typography variant="caption" color="text.secondary" mt={1} display="block">
                Complete your profile to get better AI match suggestions!
              </Typography>
            </Card>
          )}

          {/* Biological Data */}
          {profile.bio && (
            <Card variant="outlined" sx={{ mt: 4, p: 3, borderRadius: 4, bgcolor: theme.palette.mode === 'dark' ? 'rgba(59, 130, 246, 0.05)' : 'rgba(59, 130, 246, 0.02)', borderColor: 'rgba(59, 130, 246, 0.2)' }}>
              <Typography variant="overline" fontWeight={800} color="primary.main" display="flex" alignItems="center" gap={1} mb={1}>
                <User size={14} /> About Me
              </Typography>
              <Typography variant="body1" color="text.primary" sx={{ lineHeight: 1.7 }}>
                {profile.bio}
              </Typography>
            </Card>
          )}

          {/* Environmental Loadouts */}
          <Grid container spacing={3} sx={{ mt: 1 }}>
            <Grid item xs={12} md={6}>
              <Card variant="outlined" sx={{ borderRadius: 4, height: '100%', p: 3, bgcolor: 'background.paper', '&:hover': { boxShadow: theme.shadows[2] }, transition: 'box-shadow 0.2s' }}>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', pb: 2, mb: 2, borderBottom: 1, borderColor: 'divider' }}>
                  <Typography variant="h6" fontWeight={800} color="text.primary" display="flex" alignItems="center" gap={1}>
                    <BookOpen size={20} color={theme.palette.secondary.main} /> Academic Mastery
                  </Typography>
                  <Button size="small" variant="outlined" onClick={() => setMapOpen(true)} sx={{ borderRadius: '100px', fontWeight: 800 }}>
                    🧠 Neural Map
                  </Button>
                </Box>
                {profile.subjects?.length > 0 ? (
                  <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                    {profile.subjects.map(s => (
                      <Chip key={s} label={s} sx={{ fontWeight: 600, borderRadius: 2 }} color="primary" variant="outlined" />
                    ))}
                  </Box>
                ) : (
                  <Typography variant="body2" color="text.disabled" fontStyle="italic">No subjects added.</Typography>
                )}

                {/* Endorsements System */}
                <Box sx={{ mt: 4, pt: 3, borderTop: 1, borderColor: 'divider' }}>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                    <Typography variant="subtitle2" fontWeight={800} color="text.primary">Endorsements</Typography>
                    {targetId !== me?._id && (
                      <Button onClick={() => {
                        const skill = window.prompt("What subject/skill are you endorsing them for?");
                        if (!skill) return;
                        api.post(`/gamification/endorse/${targetId}`, { skill })
                          .then(res => {
                            toast.success(`Endorsed ${profile.name} for ${skill}!`);
                            setEndorsements([...endorsements, { ...res.data, endorserId: me }]);
                          })
                          .catch(() => toast.error('Failed or already endorsed'));
                      }} size="small" variant="outlined" sx={{ borderRadius: 2, fontWeight: 700 }}>
                        + Endorse
                      </Button>
                    )}
                  </Box>
                  <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                    {endorsements.length === 0 ? (
                       <Typography variant="caption" color="text.secondary">No endorsements yet.</Typography>
                    ) : (
                      // Group by skill and count
                      Object.entries(endorsements.reduce((acc, current) => {
                        acc[current.skill] = (acc[current.skill] || 0) + 1;
                        return acc;
                      }, {})).map(([skill, count]) => (
                        <Chip key={skill} label={`${skill} ${count > 1 ? `x${count}` : ''}`} sx={{ fontWeight: 700, borderRadius: 1.5, bgcolor: 'rgba(16, 185, 129, 0.1)', color: '#10b981' }} size="small" />
                      ))
                    )}
                  </Box>
                </Box>
              </Card>
            </Grid>

            <Grid item xs={12} md={6}>
              <Card variant="outlined" sx={{ borderRadius: 4, height: '100%', p: 3, bgcolor: 'background.paper', '&:hover': { boxShadow: theme.shadows[2] }, transition: 'box-shadow 0.2s' }}>
                <Typography variant="h6" fontWeight={800} color="text.primary" display="flex" alignItems="center" gap={1} pb={2} mb={2} borderBottom={1} borderColor="divider">
                  <User size={20} color="#10b981" /> Study Info
                </Typography>
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', p: 1.5, borderRadius: 2, bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.02)' }}>
                    <Typography variant="body2" fontWeight={600} color="text.secondary">Education Tier</Typography>
                    <Chip label={profile.educationLevel} size="small" sx={{ fontWeight: 700, borderRadius: 1.5 }} />
                  </Box>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', p: 1.5, borderRadius: 2, bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.02)' }}>
                    <Typography variant="body2" fontWeight={600} color="text.secondary">Cognitive Style</Typography>
                    <Chip label={profile.studyStyle} size="small" sx={{ fontWeight: 700, borderRadius: 1.5 }} />
                  </Box>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', p: 1.5, borderRadius: 2, bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.02)' }}>
                    <Typography variant="body2" fontWeight={600} color="text.secondary">Session Pref</Typography>
                    <Chip label={profile.preferOnline ? 'Digital Online' : 'Physical Local'} size="small" color="info" sx={{ fontWeight: 700, borderRadius: 1.5 }} />
                  </Box>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', p: 1.5, borderRadius: 2, bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.02)' }}>
                    <Typography variant="body2" fontWeight={600} color="text.secondary">Network Conn.</Typography>
                    <Chip label={`${profile.connections?.length || 0} Synapses`} size="small" color="success" sx={{ fontWeight: 700, borderRadius: 1.5 }} />
                  </Box>
                </Box>
              </Card>
            </Grid>
          </Grid>

        </Box>
      </Card>

      {/* Mind Map Dialog */}
      <MindMapModal open={mapOpen} onClose={() => setMapOpen(false)} user={profile} />
    </Container>
  );
}
